import type { Verse } from '../types';

// Capítulos reais deste livro. Segue o mesmo formato de src/bible/genesis.ts:
// { n: <capítulo>: [ { n: <versículo>, text: '<texto>' }, ... ] }
export const JOSHUA_CHAPTERS: Record<number, Verse[]> = {
  1: [
    { n: 1, text: '“Kutani, endzhaku ka rifu ra Muxe, nandza wa Yehovha, Yehovha a vulavula na Yoxuwa, n’wana wa Nuni, mutirheli wa Muxe, a ku:”' },
    { n: 2, text: '“‘Muxe, nandza wa mina, u file; hikwalaho tluka, u tsemakanya Yordani leyi, wena ni vanhu lava hinkwavo, etikweni leri ndzi ri nyikaka vana va Israyele;’”' },
    { n: 3, text: '“‘ndhawu hinkwayo leyi nenge wa wena wu nga ta kandziya ehenhla ka yona, ndzi ku nyikile yona, hilaha ndzi tshembiseke Muxe;’”' },
    { n: 4, text: '“‘kusuka emananga ni Lebanoni leyi, ku fika enambyeni lowukulu, nambu wa Yufrata, tiko hinkwaro ra Vahiti, ni ku fika elwandle ra le vuxeni, ku ta va ndzilakano wa wena;’”' },
    { n: 5, text: '“‘a ku na munhu loyi a nga ta yima mahlweni ka wena masiku hinkwawo ya vutomi bya wena; hilaha ndzi veke na Muxe, ndzi ta va na wena; a nga ka a nga ku tshiki, naswona a nga ka a nga ku fularheli;’”' },
    { n: 6, text: '“‘tiyisa, u va ni xivindzi; hikuva wena u ta avelana vanhu lava tiko leri ndzi hlambanyeke ku ri nyika vatata wa vona;’”' },
    { n: 7, text: '“‘tiyisa ntsena, u va ni xivindzi lexikulu, u hlayisa ku endla hi nawu hinkwawo lowu Muxe, nandza wa mina, a ku leriseke wona; u nga hambuki eka wona, u ya exineneni kumbe eximatsini, leswaku u fambela kahle hinkwako lomu u yaka kona;’”' },
    { n: 8, text: '“‘buku leyi ya nawu a yi nga suki enon’wini wa wena, kambe u ta ehleketa ha yona nhlikanhi ni vusiku, leswaku u hlayisa ku endla hinkwaswo leswi tsaleriweke eka yona; hikuva hi nkarhi wolowo u ta endla tindlela ta wena ti fambela kahle, naswona u ta va ni vutlhari;’”' },
    { n: 9, text: '“‘a ndzi ku lerisanga? Tiyisa, u va ni xivindzi; u nga chavi, u nga rhurhumeli; hikuva Yehovha Xikwembu xa wena u na wena hinkwako lomu u yaka kona.’”' },
    { n: 10, text: '“Kutani Yoxuwa a lerisa tindhuna ta vanhu a ku:”' },
    { n: 11, text: '“‘Tsemakanyani exikarhi ka ntsonga, mi lerisa vanhu mi ku: “Tilulamiseleni swakudya, hikuva endzhaku ka masiku manharhu mi ta tsemakanya Yordani leyi, leswaku mi ya teka tiko leri Yehovha Xikwembu xa n’wina a mi nyikaka rona;”’”' },
    { n: 12, text: '“kutani Yoxuwa a vulavula na varuvene, ni vagadi, ni hafu ya rixaka ra Manase, a ku:”' },
    { n: 13, text: '“‘Tsundzukani rito leri Muxe, nandza wa Yehovha, a mi leriseke rona, a ku: “Yehovha Xikwembu xa n’wina u ta mi nyika ku rhula, u ta mi nyika tiko leri;”’”' },
    { n: 14, text: '“‘vavasati va n’wina, vana va n’wina, ni swifuwo swa n’wina va ta tshama etikweni leri Muxe a mi nyikeke rona eYordani; kambe n’wina, vavanuna hinkwenu lava nga ni matimba, mi ta tsemakanya mahlweni ka vamakwavo, mi va pfuna;’”' },
    { n: 15, text: '“‘ku fika loko Yehovha a nyika vamakwavo ku rhula, hilaha a mi nyikeke hakona, na vona va teka tiko leri Yehovha Xikwembu xa n’wina a va nyikaka rona; kutani mi ta tlhelela etikweni ra ndzhaka ya n’wina, mi tshama eka rona, leri Muxe, nandza wa Yehovha, a mi nyikeke rona eYordani, hi tlhelo ra le vuxeni;’”' },
    { n: 16, text: '“kutani va hlamula Yoxuwa va ku: ‘Hinkwaswo leswi u hi leriseke swona hi ta swi endla, naswona hinkwako lomu u hi rumaka kona hi ta ya;’”' },
    { n: 17, text: '“‘hilaha hi yingiseke Muxe hakona, hi ta ku yingisa na wena; Yehovha Xikwembu xa wena a va na wena, hilaha a veke na Muxe;’”' },
    { n: 18, text: '“‘hinkwavo lava va nga ta ala rito ra wena, va nga yingisi marito ya wena eka hinkwaswo leswi u hi lerisaka swona, va ta dlayiwa; tiyisa ntsena, u va ni xivindzi.’”' }
  ],
  2: [
    { n: 1, text: '“Kutani Yoxuwa, n’wana wa Nuni, a rhuma vavanuna vambirhi hi xihundla va suka eXitimi, a ku: ‘Yanani, mi ya languta tiko, na Yeriko.’ Kutani va ya, va fika endlwini ya wansati wa nghwavava, loyi vito ra yena a ku ri Rahaba, va tshama kwalaho;”' },
    { n: 2, text: '“kutani va byela hosi ya Yeriko va ku: ‘Wasivo, vavanuna va vana va Israyele va te laha vusiku, leswaku va ta languta tiko;’”' },
    { n: 3, text: '“kutani hosi ya Yeriko a rhuma rito eka Rahaba a ku: ‘Huma u humesa vavanuna lava va teke eka wena, hikuva va te ku ta languta tiko;’”' },
    { n: 4, text: '“kambe wansati a teka vavanuna vambirhi, a va fihla, a ku: ‘I ntiyiso, vavanuna va te eka mina, kambe a ndzi nga tivi lomu va humaka kona;’”' },
    { n: 5, text: '“‘naswona loko nkarhi wo pfala nyangwa wu fika, loko ku ri na munyama, vavanuna va humile; a ndzi tivi lomu va yaka kona; va landzeleleni, mi ta va kuma;’”' },
    { n: 6, text: '“kambe a a va tlakusile etlhelo ka yindlu, a va fihle exikarhi ka mavele ya le henhla ya yindlu;”' },
    { n: 7, text: '“kutani vavanuna va va hlongorisile hi ndlela ya Yordani, ku fika etindhawini ta mati; naswona loko lava va va hlongorisaka va humile, va pfale nyangwa.”' },
    { n: 8, text: '“Va nga si etlela, a tlhandlukela eka vona etlhelo ka yindlu;”' },
    { n: 9, text: '“a ku eka vavanuna: ‘Ndzi tiva leswaku Yehovha u mi nyikile tiko, naswona ku chava ka n’wina ku hi fikelele, naswona hinkwavo vaaki va tiko va rhurhumela hikwalaho ka n’wina;’”' },
    { n: 10, text: '“‘hikuva hi twile leswaku Yehovha u omise mati ya Lwandle ra le Dzongeni mahlweni ka n’wina loko mi huma eEgipta, ni leswi mi swi endleke eka tihosi timbirhi ta Vamori, Sihoni na Ogi, lava a va ri eYordani, lava mi va heriseke;’”' },
    { n: 11, text: '“‘loko hi swi twile, timbilu ta hina ti helile, naswona a ku ha ri na xivindzi eka munhu hi nkarhi wa n’wina; hikuva Yehovha Xikwembu xa n’wina, hi yena Xikwembu etilweni ehenhla ni le misaveni ehansi;’”' },
    { n: 12, text: '“‘hikwalaho, ndzi kombela mi hlambanya hi Yehovha, leswaku hi ku va mi ndzi endlele tintswalo, na n’wina mi ta endlela ndyangu wa tatana tintswalo; mi ndzi nyika xikombiso xa ntiyiso;’”' },
    { n: 13, text: '“‘naswona mi ta hlayisa tatana, ni mana wa mina, ni vamakwerhu va mina, ni vana va vona hinkwavo, mi ponisa vutomi bya hina eka rifu;’”' },
    { n: 14, text: '“kutani vavanuna va ku eka yena: ‘Vutomi bya hina byi ta fa ematshanweni ya n’wina, loko mi nga paluxi marito ya hina lawa; kutani loko Yehovha a hi nyika tiko leri, hi ta ku endlela tintswalo ni ntiyiso;’”' },
    { n: 15, text: '“kutani a va thela hi nkata ehenhla ka khokho, hikuva yindlu ya yena a yi ri entsongeni wa rirhangu, naswona a a tshama erirhangwini;”' },
    { n: 16, text: '“a ku eka vona: ‘Yanani entshaveni, leswaku va nga mi kumi lava va mi hlongorisaka; mi fihla kwalaho masiku manharhu, ku fika loko va tlhelela; kutani mi ta famba endleleni ya n’wina;’”' },
    { n: 17, text: '“kutani vavanuna va ku eka yena: ‘Hi ta va lava nga riki na nandzu eka xihlambanyo lexi u hi hlambanyiseke xona;’”' },
    { n: 18, text: '“‘wasivo, loko hi nghena etikweni, u ta boha nkata wa ntambhu ya ntsindza ehenhla ka khokho leri u hi theleke ha rona; u ta hlengeleta tatana ni mana wa wena, ni vamakwerhu, ni ndyangu wa tatana hinkwawo endlwini ya wena;’”' },
    { n: 19, text: '“‘kutani un’wana ni un’wana loyi a nga ta huma etinyangweni ta yindlu ya wena, ngati ya yena yi ta va ehenhla ka nhloko ya yena, naswona hi ta va lava nga riki na nandzu; naswona hinkwavo lava va nga ta va na wena endlwini, ngati ya vona yi ta va ehenhla ka nhloko ya hina, loko voko ra munhu ri va khumba;’”' },
    { n: 20, text: '“‘kambe loko u paluxa marito ya hina lawa, hi ta va lava nga riki na nandzu eka xihlambanyo lexi u hi hlambanyiseke xona;’”' },
    { n: 21, text: '“kutani a ku: ‘A swi ve hilaha mi vulaka hakona.’ Kutani a va tshika, va famba; naswona a boha nkata wa ntsindza entsongeni;”' },
    { n: 22, text: '“kutani va famba, va fika entshaveni, va tshama kwalaho masiku manharhu, ku fika loko lava va va hlongorisaka va tlhelela; lava va va hlongorisaka va va lavile hi ndlela hinkwayo, kambe a va va kumanga;”' },
    { n: 23, text: '“kutani vavanuna vambirhi va tlhelela, va rhelela entshaveni, va tsemakanya, va fika eka Yoxuwa, n’wana wa Nuni, va n’wi byela hinkwaswo leswi va humeleleke;”' },
    { n: 24, text: '“va ku eka Yoxuwa: ‘Yehovha u nyikile tiko hinkwaro evokweni ra hina; naswona vaaki hinkwavo va tiko va rhurhumela hikwalaho ka hina.’”' }
  ],
  3: [
    { n: 1, text: '“Kutani Yoxuwa a pfuka mixo, va huma eXitimi, va fika eYordani, yena ni vana va Israyele hinkwavo, va etlela kwalaho va nga si tsemakanya;”' },
    { n: 2, text: '“kutani, eku heleni ka masiku manharhu, tindhuna ti famba exikarhi ka ntsonga;”' },
    { n: 3, text: '“ti lerisa vanhu ti ku: ‘Loko mi vona areka ya ntwanano wa Yehovha Xikwembu xa n’wina, ni vaprista, Valevhi, va yi tamele, mi ta suka mi landzela yona;’”' },
    { n: 4, text: '“‘kambe ku ta va ni mpfhuka exikarhi ka n’wina ni yona, wa ku ringana ku fika ka mimbirhi ya madzana ya tikhuba; mi nga tshineli eka yona, leswaku mi tiva ndlela leyi mi nga ta famba ha yona; hikuva a mi kalanga mi famba hi ndlela leyi?’”' },
    { n: 5, text: '“Kutani Yoxuwa a ku eka vanhu: ‘Tihlawuleleni, hikuva mundzuku Yehovha u ta endla swihlamariso exikarhi ka n’wina;’”' },
    { n: 6, text: '“Yoxuwa a ku eka vaprista: ‘Tekani areka ya ntwanano, mi tsemakanya mahlweni ka vanhu.’ Kutani va teka areka ya ntwanano, va famba mahlweni ka vanhu;”' },
    { n: 7, text: '“kutani Yehovha a ku eka Yoxuwa: ‘Namuntlha ndzi ta sungula ku ku tlakusa mahlweni ka Israyele hinkwayo, leswaku va tiva leswaku hilaha ndzi veke na Muxe, ndzi ta va na wena;’”' },
    { n: 8, text: '“‘kutani u ta lerisa vaprista lava tameleke areka ya ntwanano, u ku: “Loko mi fika etlhelo ka mati ya Yordani, mi ta yima eYordani;”’”' },
    { n: 9, text: '“kutani Yoxuwa a ku eka vana va Israyele: ‘Tshinelani, mi twa marito ya Yehovha Xikwembu xa n’wina;’”' },
    { n: 10, text: '“Yoxuwa a ku: ‘Hi leswi mi nga ta tiva ha swona leswaku Xikwembu lexi hanyaka xi exikarhi ka n’wina, naswona xi ta hlongola mahlweni ka n’wina Vakanana, Vahiti, Vahivhi, Vaperizi, Vagergixi, Vamori, ni Vayebusi;’”' },
    { n: 11, text: '“‘wasivo, areka ya ntwanano wa Hosi ya misava hinkwayo yi ta tsemakanya mahlweni ka n’wina eYordani;’”' },
    { n: 12, text: '“‘hikwalaho tihlawuleleni vavanuna va vana va Israyele va khume na vambirhi, munhu un’we eka rixaka rin’we;’”' },
    { n: 13, text: '“‘naswona loko nenge wa vaprista lava tameleke areka ya Yehovha, Hosi ya misava hinkwayo, wu rhumela ematini ya Yordani, mati ya Yordani, mati lawa ma rheleke, ma ta yima, ma va xintshabyana;’”' },
    { n: 14, text: '“kutani, loko vanhu va humile etintsongeni ta vona leswaku va tsemakanya Yordani, ni vaprista va tamele areka ya ntwanano mahlweni ka vanhu;”' },
    { n: 15, text: '“kutani, loko lava va tameleke areka va fike eYordani, ni nenge wa vaprista va tamele areka wu rhumela etlhelo ka mati (naswona Yordani a a tele hi mati ku tlula hinkwako masiku ya ntshovelo), mati lawa ma rheleke ma yima, ma tlakuka ma va xintshabyana, ekusuhi ni muti wa Adama, lowu nga etlhelo ka Tsaretani;”' },
    { n: 16, text: '“ni lawa ma rheleke elwandle ra Araba, Lwandle ra Munyu, ma helile, ma hungutekile; kutani vanhu va tsemakanya va langutane ni Yeriko;”' },
    { n: 17, text: '“kutani vaprista lava tameleke areka ya ntwanano wa Yehovha va yima va tiyile exikarhi ka Yordani, naswona Israyele hinkwayo a va tsemakanya hi misava leyi omeke, ku fika loko vanhu hinkwavo va heta ku tsemakanya Yordani.”' }
  ],
  4: [
    { n: 1, text: '“Kutani, loko vanhu hinkwavo va hete ku tsemakanya Yordani, Yehovha a vulavula na Yoxuwa, a ku:”' },
    { n: 2, text: '“‘Tihlawuleleni vavanuna va vana va Israyele va khume na vambirhi, munhu un’we eka rixaka rin’we;’”' },
    { n: 3, text: '“‘mi va lerisa mi ku: “Ti tekela laha, exikarhi ka Yordani, lomu vaprista va yimaka va tiyile, maribye ya khume na mambirhi, mi ta va rhwala, mi va veka endhawini leyi mi nga ta etlela eka yona nimadyambu;”’”' },
    { n: 4, text: '“kutani Yoxuwa a vitana vavanuna va khume na vambirhi, lava a va hlawuleke eka vana va Israyele, munhu un’we eka rixaka rin’we;”' },
    { n: 5, text: '“Yoxuwa a ku eka vona: ‘Tsemakanyani mahlweni ka areka ya Yehovha Xikwembu xa n’wina, mi fika exikarhi ka Yordani, mi ti tekela un’we-un’we ribye ra n’wina, hi ku ya hi ntsengo wa tinyimba ta vana va Israyele;’”' },
    { n: 6, text: '“‘leswaku leswi swi va xikombiso exikarhi ka n’wina; loko vana va n’wina va vutisa va ku: “Maribye lawa ma vula yini eka n’wina?”’”' },
    { n: 7, text: '“‘kutani mi va hlamula: “Mati ya Yordani ma hungutekile mahlweni ka areka ya ntwanano wa Yehovha; loko yi tsemakanya Yordani, mati ya Yordani ma hungutekile; kutani maribye lawa ma ta va xitsundzuxo eka vana va Israyele hilaha ku nga heriki;”’”' },
    { n: 8, text: '“kutani vana va Israyele va endla hilaha Yoxuwa a va leriseke hakona, va teka maribye ya khume na mambirhi exikarhi ka Yordani, hilaha Yehovha a byeleke Yoxuwa hakona, hi ku ya hi ntsengo wa tinyimba ta vana va Israyele, va ma rhwala va ya na vona endhawini leyi va etleleke eka yona, va ma veka kwalaho;”' },
    { n: 9, text: '“Yoxuwa a veka maribye ya khume na mambirhi exikarhi ka Yordani, laha vaprista lava tameleke areka ya ntwanano va yimeke kona; naswona ma kona kwalaho ku fika namuntlha;”' },
    { n: 10, text: '“vaprista lava tameleke areka va yima exikarhi ka Yordani, ku fika loko hinkwaswo swi hetiwile leswi Yehovha a leriseke Yoxuwa ku byela vanhu, hi ku ya hi hinkwaswo leswi Muxe a leriseke Yoxuwa; kutani vanhu va hatlisa va tsemakanya;”' },
    { n: 11, text: '“kutani, loko vanhu hinkwavo va hete ku tsemakanya, areka ya Yehovha ni vaprista va tsemakanya mahlweni ka vanhu;”' },
    { n: 12, text: '“vana va Ruvene, vana va Gadi, ni hafu ya rixaka ra Manase va tsemakanya va hlomile, mahlweni ka vana va Israyele, hilaha Muxe a va byeleke hakona;”' },
    { n: 13, text: '“kuma-khume wa madzana ya vavanuna lava hlomeke va tsemakanya mahlweni ka Yehovha, leswaku va lwa, va fika etiphaleni ta Yeriko;”' },
    { n: 14, text: '“hi siku rero Yehovha a tlakusa Yoxuwa mahlweni ka Israyele hinkwayo; va n’wi chavile hilaha va chaveke Muxe hakona, masiku hinkwawo ya vutomi bya yena;”' },
    { n: 15, text: '“Yehovha a vulavula na Yoxuwa a ku:”' },
    { n: 16, text: '“‘Lerisa vaprista lava tameleke areka ya ntwanano, leswaku va huma eYordani;’”' },
    { n: 17, text: '“kutani Yoxuwa a lerisa vaprista a ku: ‘Humani eYordani;’”' },
    { n: 18, text: '“kutani, loko vaprista lava tameleke areka ya ntwanano wa Yehovha va humile exikarhi ka Yordani, ni nenge wa vaprista wu rhumele etikweni ro oma, mati ya Yordani ma tlhelela etindhawini ta vona, ma tlhela ma khuluka hilaha ma khulukeke hakona khale;”' },
    { n: 19, text: '“vanhu va humile eYordani hi siku ra khume ra n’weti wo sungula, va etlela eGilgala, etlhelo ka vuxa bya Yeriko;”' },
    { n: 20, text: '“maribye lawa ya khume na mambirhi, lawa va ma teke eYordani, Yoxuwa a ma veka eGilgala;”' },
    { n: 21, text: '“a ku eka vana va Israyele: ‘Loko vana va n’wina va vutisa vatata wa vona enkarhini lowu taka, va ku: “Maribye lawa ma vula yini?”’”' },
    { n: 22, text: '“‘mi ta byela vana va n’wina, mi ku: “Israyele u tsemakanyile Yordani hi misava leyi omeke;”’”' },
    { n: 23, text: '“‘hikuva Yehovha Xikwembu xa n’wina u omise mati ya Yordani mahlweni ka n’wina, ku fika loko mi heta ku tsemakanya, hilaha Yehovha Xikwembu xa n’wina a endleke hakona elwandle ra le dzongeni, leri a nga ri omisa mahlweni ka hina, ku fika loko hi heta ku tsemakanya;’”' },
    { n: 24, text: '“‘leswaku matiko hinkwawo ya misava ma tiva leswaku voko ra Yehovha i ra matimba, leswaku mi chava Yehovha Xikwembu xa n’wina masiku hinkwawo.’”' }
  ],
  5: [
    { n: 1, text: '“Kutani, loko tihosi hinkwato ta Vamori, leti a ti ri etlhelo ka vuxa bya Yordani, ni tihosi hinkwato ta Vakanana, leti a ti ri etlhelo ka lwandle, ti twa leswaku Yehovha u omise mati ya Yordani mahlweni ka vana va Israyele ku fika loko va heta ku tsemakanya, timbilu ta vona ti helile, naswona a ku ha ri na xivindzi eka vona hikwalaho ka vana va Israyele;”' },
    { n: 2, text: '“hi nkarhi wolowo Yehovha a ku eka Yoxuwa: ‘Tiendlela mimese ya maribye, u tlhela u yenga vana va Israyele;’”' },
    { n: 3, text: '“kutani Yoxuwa a tiendlela mimese ya maribye, a yenga vana va Israyele etlhelo ka nhlohlorhi ya maribye;”' },
    { n: 4, text: '“naswona lexi hi xona xikongomelo xa leswi Yoxuwa a nga yenga ha swona: vanhu hinkwavo lava humeke eEgipta, vavanuna, vavanuna hinkwavo lava nga ni matimba, va file emananga hi ndlela, loko va humile eEgipta;”' },
    { n: 5, text: '“vanhu hinkwavo lava humeke va yengiwile, kambe vanhu hinkwavo lava tswaleriweke emananga hi ndlela, loko va humile eEgipta, a va nga yengiwanga;”' },
    { n: 6, text: '“hikuva vana va Israyele va fambe emananga hi malembe ya mune-ntse-mune, ku fika loko tiko hinkwaro, vavanuna hinkwavo lava nga ni matimba lava humeke eEgipta, va fa, hikuva va nga yingisanga rito ra Yehovha, lava Yehovha a nga hlambanya leswaku a nga ka a nga va kombi tiko leri Yehovha a hlambanyeke ku ri nyika vatata wa vona, tiko leri khulukaka ntswamba ni vulombe;”' },
    { n: 7, text: '“kutani vana va vona, lava a va yimisele vona, Yoxuwa a va yengile; hikuva a va nga yengiwanga, hikuva a va nga va yenganga hi ndlela;”' },
    { n: 8, text: '“kutani, loko va hete ku yenga tiko hinkwaro, va tshame etindhawini ta vona entsongeni, ku fika loko va hola;”' },
    { n: 9, text: '“Yehovha a ku eka Yoxuwa: ‘Namuntlha ndzi susile xihlambanyo xa Egipta ehenhla ka n’wina.’ Kutani vito ra ndhawu yoleyo ri vuriwile Gilgala, ku fika namuntlha;”' },
    { n: 10, text: '“vana va Israyele va tshame eGilgala, va endla nkhuvo wa Paska hi siku ra khume na mune ra n’weti, nimadyambu, etiphaleni ta Yeriko;”' },
    { n: 11, text: '“va dyile mihandzu ya tiko hi siku leri landzeleke ra Paska, mavele ni makanyi hi siku rero;”' },
    { n: 12, text: '“kutani mana a a nga ha humi hi siku leri landzeleke, loko va dyile mihandzu ya tiko; vana va Israyele a va nga ha na mana, va dyile mihandzu ya tiko ra Kanana hi lembe rero;”' },
    { n: 13, text: '“kutani, loko Yoxuwa a ri etlhelo ka Yeriko, a tlakusa mahlo ya yena, a languta, wasivo, wanuna a yime mahlweni ka yena, a tamele banga leri a ri koka evokweni ra yena; Yoxuwa a tshinela eka yena, a ku eka yena: ‘U wa hina kumbe u wa valala va hina?’”' },
    { n: 14, text: '“a ku: ‘A ndzi wa valala, kambe ndzi nkulukumba wa mavuthu ya Yehovha; ndzi te sweswi.’ Kutani Yoxuwa a wela ehansi, a nkhinsamela, a ku eka yena: ‘Xana nkulukumba wa mina u ku yini eka nandza wa yena?’”' },
    { n: 15, text: '“nkulukumba wa mavuthu ya Yehovha a ku eka Yoxuwa: ‘Susa tintshangu ta wena emilengeni ya wena, hikuva ndhawu leyi u yimeke eka yona i yo kwetsima.’ Kutani Yoxuwa a endla tano.”' }
  ],
  6: [
    { n: 1, text: '“Yeriko a yi pfariwile swinene hikwalaho ka vana va Israyele; a ku na loyi a humaka, naswona a ku na loyi a nghenaka;”' },
    { n: 2, text: '“Yehovha a ku eka Yoxuwa: ‘Wasivo, ndzi nyikile Yeriko evokweni ra wena, ni hosi ya yona, ni vavanuna lava nga ni matimba;’”' },
    { n: 3, text: '“‘mi ta rhendzela muti, vavanuna hinkwenu lava nga ni matimba, mi rhendzela muti kamun’we; mi ta endla tano hi masiku ya nkombo;’”' },
    { n: 4, text: '“‘vaprista va khume na mambirhi va ta tamele timhalamhala ta nkombo mahlweni ka areka, kutani hi siku ra nkombo mi ta rhendzela muti kankombo, vaprista va chika timhalamhala;’”' },
    { n: 5, text: '“‘kutani, loko va chika mhalamhala hi nkarhi lowu leheke, loko mi twa mpfumawulo wa mhalamhala, vanhu hinkwavo va ta huwelela hi huwelelo lerikulu; kutani rirhangu ra muti ri ta wa, kutani vanhu va ta tlakuka, un’we-un’we mahlweni ka yena;’”' },
    { n: 6, text: '“Yoxuwa, n’wana wa Nuni, a vitana vaprista, a ku eka vona: ‘Tekani areka ya ntwanano, mi veka vaprista va khume na mambirhi va tamele timhalamhala ta nkombo mahlweni ka areka ya Yehovha;’”' },
    { n: 7, text: '“a ku eka vanhu: ‘Tlakukani, mi rhendzela muti, naswona loyi a hlomeke a a tsemakanye mahlweni ka areka ya Yehovha;’”' },
    { n: 8, text: '“kutani, loko Yoxuwa a vulavurile eka vanhu, vaprista va khume na mambirhi, lava va tameleke timhalamhala ta nkombo, va tsemakanya mahlweni ka Yehovha, va chika timhalamhala, naswona areka ya ntwanano wa Yehovha yi va landzela;”' },
    { n: 9, text: '“lava va hlomeke va famba mahlweni ka vaprista lava va chikaka timhalamhala, naswona lava va landzelaka va landzela areka, va ri karhi va chika timhalamhala va famba;”' },
    { n: 10, text: '“Yoxuwa a lerisa vanhu a ku: ‘Mi nga huweleli, mi nga twisi rito ra n’wina, naswona rito ri nga humi enon’wini wa n’wina, ku fika siku leri ndzi nga ta ku eka n’wina: “Huweleleni!” Kutani mi ta huwelela;’”' },
    { n: 11, text: '“kutani areka ya Yehovha yi rhendzela muti, yi rhendzela kamun’we, va tlhelela entsongeni, va etlela entsongeni;”' },
    { n: 12, text: '“Yoxuwa a pfuka mixo, vaprista va teka areka ya Yehovha;”' },
    { n: 13, text: '“vaprista va khume na mambirhi, lava va tameleke timhalamhala ta nkombo mahlweni ka areka ya Yehovha, va famba va ri karhi va chika timhalamhala, naswona lava va hlomeke va famba mahlweni ka vona, naswona lava va landzelaka va landzela areka ya Yehovha, va ri karhi va chika timhalamhala va famba;”' },
    { n: 14, text: '“va rhendzela muti kamun’we hi siku ra vumbirhi, va tlhelela entsongeni; va endla tano hi masiku ya nkombo;”' },
    { n: 15, text: '“kutani, hi siku ra nkombo, va pfuka mixo, va rhendzela muti hi mukhuva lowu, kankombo; hi siku rero ntsena va rhendzela muti kankombo;”' },
    { n: 16, text: '“kutani, hi nkarhi wa nkombo, vaprista va chika timhalamhala, Yoxuwa a ku eka vanhu: ‘Huweleleni; hikuva Yehovha u mi nyikile muti;’”' },
    { n: 17, text: '“‘naswona muti wu ta va lowu rhukeriweke Yehovha, wona ni hinkwaswo leswi nga eka wona; ntsena Rahaba, wansati wa nghwavava, u ta hanya, yena ni hinkwavo lava nga na yena endlwini, hikuva u fihle varhumiwa lava hi va rhumeleke;’”' },
    { n: 18, text: '“‘kambe n’wina, mi tiyisa mi nga tshuki mi khumba leswi rhukeriweke, mi nga tshuki mi teka nchumu eka leswi rhukeriweke, leswaku mi nga endli ntsonga wa Israyele wu va lowu rhukeriweke, mi wu kavanyeta;’”' },
    { n: 19, text: '“‘naswona silivhere hinkwayo, ni nsuku, ni swilo swa nsuku ni swa silivhere, swi ta va swa ku kwetsima eka Yehovha; swi ta nghena exikhwameni xa Yehovha;’”' },
    { n: 20, text: '“kutani vanhu va huwelela, naswona va chika timhalamhala; kutani, loko vanhu va twa mpfumawulo wa mhalamhala, vanhu va huwelela hi huwelelo lerikulu, rirhangu ri wa, naswona vanhu va tlakuka, un’we-un’we mahlweni ka yena, va nghena emutini;”' },
    { n: 21, text: '“va herisa hinkwaswo leswi a swi ri emutini, vavanuna ni vavasati, vana ni vadyuhari, ni tihomu, ni tinyimpfu, ni timbuti, hi banga;”' },
    { n: 22, text: '“kambe Yoxuwa a ku eka vavanuna vambirhi lava va nga languta tiko: ‘Yanani endlwini ya wansati wa nghwavava, mi humesa wansati kwalaho ni hinkwavo lava nga na yena, hilaha mi hlambanyeke hakona;’”' },
    { n: 23, text: '“vavanuna lava va languteke tiko va nghena, va humesa Rahaba, ni tatana wa yena, ni mana wa yena, ni vamakwerhu, ni hinkwavo lava a va ri na yena; va humesa ni ndyangu wa yena hinkwawo, va va veka etlhelo ka ntsonga wa Israyele;”' },
    { n: 24, text: '“va hisa muti ni hinkwaswo leswi a swi ri eka wona hi ndzilo; ntsena silivhere, ni nsuku, ni swilo swa nsuku ni swa silivhere, va swi veka exikhwameni xa yindlu ya Yehovha;”' },
    { n: 25, text: '“Yoxuwa a ponisa Rahaba, wansati wa nghwavava, ni ndyangu wa tatana wa yena, ni hinkwavo lava a va ri na yena; a tshama exikarhi ka Israyele ku fika namuntlha, hikuva u fihle varhumiwa lava Yoxuwa a va rhumeleke ku languta Yeriko;”' },
    { n: 26, text: '“Yoxuwa a hlambanya hi nkarhi wolowo a ku: ‘A rhukeriwe munhu loyi a nga ta pfuka, a aka muti lowu wa Yeriko; u ta veka masungulo ya wona ehenhla ka mativula ya yena, u ta veka tinyangwa ta wona ehenhla ka n’wana wa yena wa le ndzhaku;’”' },
    { n: 27, text: '“Yehovha a a ri na Yoxuwa, naswona vito ra yena ri hangalake etikweni hinkwaro.”' }
  ],
7: [
    { n: 1, text: '“Kambe vana va Israyele va endle xidyoho eka leswi rhukeriweke; hikuva Akani, n’wana wa Karmi, n’wana wa Zabdi, n’wana wa Zera, wa rixaka ra Yuda, u teke swilo leswi rhukeriweke; kutani vukari bya Yehovha byi pfukela vana va Israyele;”' },
    { n: 2, text: '“Yoxuwa a rhuma vavanuna va suka eYeriko va ya eAyi, leyi nga etlhelo ka Betheni, hi tlhelo ra le vuxeni bya Beti-Aveni, a ku eka vona: ‘Tlhandlukani, mi ya languta tiko.’ Kutani vavanuna va tlhandluka, va ya languta Ayi;”' },
    { n: 3, text: '“va tlhelela eka Yoxuwa, va ku eka yena: ‘Vanhu hinkwavo va nga ka va nga tlhandlukeli kwalaho; a ku ye vavanuna va madzana mambirhi kumbe nharhu, va ya ba Ayi; u nga endli vanhu hinkwavo va karhala kwalaho, hikuva i vatsongo;’”' },
    { n: 4, text: '“kutani va tlhandluka kwalaho va vanhu va kwalomu ka magidi manharhu, kambe va tsutsumela mahlweni ka vavanuna va Ayi;”' },
    { n: 5, text: '“vavanuna va Ayi va dlaye vavanuna va kwalomu ka makume-mbirhi na nkombo va eka vona, va va hlongorisa va suka enyangweni ku fika eXebarimi, va va ba entshaveni; kutani timbilu ta vanhu ti helile, ti fana ni mati;”' },
    { n: 6, text: '“kutani Yoxuwa a handzula swiambalo swa yena, a wela ehansi hi nghohe mahlweni ka areka ya Yehovha ku fika nimadyambu, yena ni vadyuhari va Israyele, va chela ntshuri ehenhla ka tinhloko ta vona;”' },
    { n: 7, text: '“Yoxuwa a ku: ‘Oho, Hosi Yehovha! U tsemakanyise vanhu lava Yordani hi xikongomelo xihi, leswaku u hi nyika evokweni ra Vamori, leswaku va hi herisa? Oho, a hi tshame le Yordani;’”' },
    { n: 8, text: '“‘oho, Hosi! Ndzi nga ku yini, endzhaku ka loko Israyele a balekile mahlweni ka valala va yena?’”' },
    { n: 9, text: '“‘Vakanana ni vaaki hinkwavo va tiko va ta twa, va hi rhendzela, va susa vito ra hina emisaveni; kutani u ta endla yini hi vito ra wena lerikulu?’”' },
    { n: 10, text: '“Yehovha a ku eka Yoxuwa: ‘Pfuka; u wela yini ehansi hi nghohe?’”' },
    { n: 11, text: '“‘Israyele u dyohile, naswona va tlulile ntwanano wa mina lowu ndzi va leriseke wona; va teke swilo leswi rhukeriweke, va yivile, va hembe, va swi veka exikarhi ka swilo swa vona;’”' },
    { n: 12, text: '“‘hikwalaho vana va Israyele a va nga ta yima mahlweni ka valala va vona, va ta baleka mahlweni ka valala va vona, hikuva va vuyile va va swilo leswi rhukeriweke; a ndzi nga ha vi na n’wina, loko mi nga herisi leswi rhukeriweke exikarhi ka n’wina;’”' },
    { n: 13, text: '“‘pfuka, u hlawula vanhu, u ku: “Tihlawuleleni mundzuku, hikuva Yehovha Xikwembu xa Israyele u ku tano: ‘Ku ni leswi rhukeriweke exikarhi ka n’wina, Israyele; a mi nga ta yima mahlweni ka valala va n’wina, ku fika loko mi susa leswi rhukeriweke exikarhi ka n’wina;’”’”' },
    { n: 14, text: '“‘mundzuku mi ta tshinela hi tinyimba ta n’wina; kutani rixaka leri Yehovha a nga ta ri hlawula ri ta tshinela hi mindyangu ya rona; naswona ndyangu lowu Yehovha a nga ta wu hlawula wu ta tshinela hi vavanuna va wona;’”' },
    { n: 15, text: '“‘kutani loyi a nga ta kumeka a ri na leswi rhukeriweke u ta hisiwa hi ndzilo, yena ni hinkwaswo leswi a nga na swona, hikuva u tlulile ntwanano wa Yehovha, ni hikuva u endle xihoxo exikarhi ka Israyele;’”' },
    { n: 16, text: '“kutani Yoxuwa a pfuka mixo, a tisa Israyele hi tinyimba ta vona, kutani rixaka ra Yuda ri hlawuriwa;”' },
    { n: 17, text: '“a tisa mindyangu ya Yuda, kutani a hlawula ndyangu wa Vazera; a tisa ndyangu wa Vazera hi vavanuna, kutani Zabdi a hlawuriwa;”' },
    { n: 18, text: '“a tisa ndyangu wa yena hi vavanuna, kutani Akani, n’wana wa Karmi, n’wana wa Zabdi, n’wana wa Zera, wa rixaka ra Yuda, a hlawuriwa;”' },
    { n: 19, text: '“Yoxuwa a ku eka Akani: ‘N’wananga, ndzi kombela u dzunisa Yehovha Xikwembu xa Israyele, u n’wi byela ntiyiso, u ndzi byela leswi u nga swi endla; u nga ndzi fihleli nchumu;’”' },
    { n: 20, text: '“Akani a hlamula Yoxuwa, a ku: ‘I ntiyiso, ndzi dyohile eka Yehovha Xikwembu xa Israyele, ndzi endle xileswi ni xileswi;’”' },
    { n: 21, text: '“‘loko ndzi vona exikarhi ka swilo leswi hlotekeke, nguvu ya le Xinarhi ya nkoka, ni swiketi swa silivhere swa magidi mambirhi, ni mupfupfu wa nsuku wa ntlhanu wa madzana ya xiketi, ndzi swi navelerile, ndzi swi teka; wasivo, swi fihliwe exikarhi ka tende ra mina, silivhere yi le hansi ka swona;’”' },
    { n: 22, text: '“Yoxuwa a rhuma varhumiwa, va tsutsumela etendeni; naswona a a fihle swi ri exikarhi ka tende ra yena, silivhere yi le hansi ka swona;”' },
    { n: 23, text: '“va swi teka exikarhi ka tende, va swi tisa eka Yoxuwa ni vana va Israyele, va swi hlatlha mahlweni ka Yehovha;”' },
    { n: 24, text: '“Yoxuwa a teka Akani, n’wana wa Zera, ni silivhere, ni nguvu, ni mupfupfu wa nsuku, ni vana va yena, ni vanhwana va yena, ni tihomu ta yena, ni timbayi ta yena, ni timbuti ta yena, ni tende ra yena, ni hinkwaswo leswi a a ri na swona, ni Israyele hinkwayo na yena, va ya na swona enkoveni wa Akoro;”' },
    { n: 25, text: '“Yoxuwa a ku: ‘Hikwalaho ka yini u hi vavise? Yehovha u ta ku vavisa namuntlha.’ Kutani Israyele hinkwayo a va kanda hi maribye, va va hisa hi ndzilo, va va kanda hi maribye;”' },
    { n: 26, text: '“va n’wi hlayela ntsandza wa maribye lowukulu, wu kona ku fika namuntlha. Kutani Yehovha a huma eka vukari bya yena lebyikulu. Hikwalaho vito ra ndhawu yoleyo ri vuriwa nkova wa Akoro, ku fika namuntlha.”' }
  ],
  8: [
    { n: 1, text: '“Yehovha a ku eka Yoxuwa: ‘U nga chavi, u nga rhurhumeli; teka vanhu hinkwavo lava nga ni matimba, u tlhandluka, u ya eAyi; wasivo, ndzi nyikile evokweni ra wena hosi ya Ayi, ni vanhu va yona, ni muti wa yona, ni tiko ra yona;’”' },
    { n: 2, text: '“‘u ta endla eAyi ni hosi ya yona, hilaha u endleke hakona eYeriko ni hosi ya yona; ntsena swifuwo swa yona ni swilo swa yona u ta tisungulela swona; tiyisa, u veka vatshami va le ndzhaku va muti;’”' },
    { n: 3, text: '“Yoxuwa a pfuka, ni vanhu hinkwavo lava nga ni matimba, leswaku va tlhandluka va ya eAyi; Yoxuwa a hlawula vavanuna va magidi manharhu, lava va matimba, a va rhuma vusiku;”' },
    { n: 4, text: '“a va lerisa a ku: ‘Wasivo, mi ta va mi le ndzhaku ka muti, mi nga tshami kule swinene ni muti, hinkwenu mi ta va mi lungile;’”' },
    { n: 5, text: '“‘kutani mina ni vanhu hinkwavo lava nga na mina hi ta tshinela emutini; naswona loko va huma va hi hlongorisa, hilaha va endleke hakona eku sunguleni, hi ta baleka mahlweni ka vona;’”' },
    { n: 6, text: '“‘va ta hi landzela, ku fika loko hi va koka va huma emutini, hikuva va ta ku: “Va baleka mahlweni ka hina, hilaha va endleke hakona eku sunguleni;” kutani hi ta baleka mahlweni ka vona;’”' },
    { n: 7, text: '“‘kutani mi ta huma laha mi fihlakeleke kona, mi teka muti, hikuva Yehovha Xikwembu xa n’wina u ta wu nyika evokweni ra n’wina;’”' },
    { n: 8, text: '“‘kutani, loko mi teke muti, mi ta hisa muti hi ndzilo; mi ta endla hilaha rito ra Yehovha ri vulaka hakona; wasivo, ndzi mi lerisile;’”' },
    { n: 9, text: '“Yoxuwa a va rhuma, va ya laha va nga ta fihla kona, va tshama exikarhi ka Betheni na Ayi, hi tlhelo ra le vuxeni bya Ayi; kambe Yoxuwa a etlela exikarhi ka vanhu vusiku byebyo;”' },
    { n: 10, text: '“Yoxuwa a pfuka mixo, a hlengeleta vanhu, a tlhandluka, yena ni vadyuhari va Israyele, mahlweni ka vanhu va ya eAyi;”' },
    { n: 11, text: '“ni vanhu hinkwavo lava nga ni matimba lava a va ri na yena va tlhandluka, va tshinela, va fika mahlweni ka muti, va tshama hi tlhelo ra le n’walungwini bya Ayi, naswona a ku ri na nkova exikarhi ka vona na Ayi;”' },
    { n: 12, text: '“a teka vavanuna va magidi manharhu, a va veka laha va nga ta fihla kona, exikarhi ka Betheni na Ayi, hi tlhelo ra le n’walungwini bya muti;”' },
    { n: 13, text: '“kutani va lulamisa vanhu hinkwavo lava a va ri entsongeni, ni vatshami va le ndzhaku va muti, va tshinela hi tlhelo ra le n’walungwini bya muti; Yoxuwa a famba vusiku byebyo exikarhi ka nkova;”' },
    { n: 14, text: '“kutani, loko hosi ya Ayi yi swi vonile, va hatlisa va huma mixo, va ya lwa na Israyele, hosi ni vanhu hinkwavo va muti, enkarhini lowu vekiweke, mahlweni ka nkova; kambe a a nga swi tivi leswaku ku na vatshami va le ndzhaku va muti;”' },
    { n: 15, text: '“Yoxuwa ni Israyele hinkwavo va tiendla tanihi lava hluriweke, va baleka hi ndlela ya emananga;”' },
    { n: 16, text: '“kutani vanhu hinkwavo lava a va ri emutini va vitaneriwa ku va hlongorisa; va hlongorisa Yoxuwa, va kokela ekule ni muti;”' },
    { n: 17, text: '“a ku na munhu loyi a seleke eAyi ni le Betheni, loyi a nga humangiki ku landzela Israyele; va tshika muti wu pfulekile, va hlongorisa Israyele;”' },
    { n: 18, text: '“Yehovha a ku eka Yoxuwa: ‘Tlakusa tlhari leri nga evokweni ra wena ehenhla ka Ayi, hikuva ndzi ta wu nyika evokweni ra wena.’ Yoxuwa a tlakusa tlhari leri a a ri na rona evokweni ra yena ehenhla ka muti;”' },
    { n: 19, text: '“vatshami va le ndzhaku va huma hi ku hatlisa laha va nga fihla kona, va tsutsumela, va nghena emutini, va wu teka, va hatlisa va wu hisa hi ndzilo;”' },
    { n: 20, text: '“vavanuna va Ayi va languta ndzhaku, va vona ndzilo wa muti wu tlhandluka ku ya etilweni, naswona a ku ha ri na xivindzi eka vona ku baleka laha ni laha; kutani vanhu lava a va baleka hi ndlela ya emananga va tlhelela eka lava va va hlongorisaka;”' },
    { n: 21, text: '“loko Yoxuwa ni Israyele hinkwavo va vonile leswaku vatshami va le ndzhaku va teke muti, ni leswaku ndzilo wa muti wu tlhandlukile, va tlhelela, va ba vavanuna va Ayi;”' },
    { n: 22, text: '“kambe vanhu va muti va huma va ya hlanganisa na vona, va va exikarhi ka Israyele, van’wana va ri laha, van’wana va ri laha; va va ba, va nga tshiki munhu a baleka ni un’we;”' },
    { n: 23, text: '“va khoma hosi ya Ayi, va yi tisa eka Yoxuwa;”' },
    { n: 24, text: '“kutani, loko Israyele a hete ku dlaya vaaki hinkwavo va Ayi entshaveni ni le mananga lomu va va hlongoriseke kona, va tlhelela hinkwavo eAyi, va ba hi banga;”' },
    { n: 25, text: '“hinkwavo lava va dlayiweke hi siku rero, vavanuna ni vavasati, a va ri magidi ya khume na mambirhi, vanhu hinkwavo va Ayi;”' },
    { n: 26, text: '“Yoxuwa a nga tlherisanga voko ra yena leri a a tlakuse tlhari ha rona, ku fika loko a hete ku herisa vaaki hinkwavo va Ayi;”' },
    { n: 27, text: '“ntse swifuwo ni swilo swa muti, vana va Israyele va tisungulela swona, hilaha Yehovha a leriseke Yoxuwa hakona;”' },
    { n: 28, text: '“Yoxuwa a hisa Ayi, a yi endla xintshabyana hilaha ku nga heriki, vutshamo bya ku fika namuntlha;”' },
    { n: 29, text: '“a hayeka hosi ya Ayi emunxini ku fika nimadyambu; kutani nimadyambu Yoxuwa a lerisa leswaku va susa ntsumbu wa yona emunxini, va wu cukumeta enyangweni wa muti, va wu hlayela ntsandza wa maribye lowukulu, wu kona ku fika namuntlha.”' }
  ],
  9: [
    { n: 1, text: '“Kutani, loko tihosi hinkwato leti a ti ri eYordani, etintshaveni, etihoveni, ni le tlhelo hinkwaro ra lwandle lerikulu mahlweni ka Lebanoni, Vahiti, Vamori, Vakanana, Vaperizi, Vahivhi, ni Vayebusi, ti twile leswi;”' },
    { n: 2, text: '“ti hlengeletana ti ri xin’we, ti ya lwa na Yoxuwa ni Israyele hi mbilu yin’we;”' },
    { n: 3, text: '“kambe vaaki va Gibiyoni va twile leswi Yoxuwa a endleke hakona eYeriko ni le Ayi;”' },
    { n: 4, text: '“va endla xitinyu, va ya va tiendla tanihi varhumiwa, va teka tinxowa leti dyuhaleke ehenhla ka timbulu tiyimpfu ta vona, ni mikwama ya vhinyo leyi dyuhaleke, leyi handzukeke, leyi bohiweke;”' },
    { n: 5, text: '“ni tintangu leti dyuhaleke, leti nga ni swisibi, ehenhla ka milenge ya vona, ni swiambalo leswi dyuhaleke ehenhla ka vona; naswona swakudya hinkwaswo swa vona swa khale a swi omile, swi ri swa ku bola;”' },
    { n: 6, text: '“va ya eka Yoxuwa entsongeni eGilgala, va ku eka yena ni vavanuna va Israyele: ‘Hi huma etikweni ra le kule; hikwalaho, endlani ntwanano na hina;’”' },
    { n: 7, text: '“vavanuna va Israyele va ku eka Vahivhi: ‘Kumbexana mi tshama exikarhi ka hina; ndzi nga endla ntwanano na n’wina hi ndlela yihi?’”' },
    { n: 8, text: '“va ku eka Yoxuwa: ‘Hi malandza ya wena.’ Yoxuwa a ku eka vona: ‘Mi vana va mani, naswona mi huma kwihi?’”' },
    { n: 9, text: '“va ku eka yena: ‘Lirhandzu ra Yehovha Xikwembu xa wena ri hume etikweni ra le kule swinene eka malandza ya wena, hikuva hi twile leswaku u wa matimba, ni hinkwaswo leswi u swi endleke eEgipta;’”' },
    { n: 10, text: '“‘ni hinkwaswo leswi u swi endleke eka tihosi timbirhi ta Vamori, Sihoni, hosi ya Xesiboni, ni Ogi, hosi ya Baxani, loyi a a ri eAxtaroti;’”' },
    { n: 11, text: '“‘hikwalaho vadyuhari va hina ni vaaki hinkwavo va tiko ra hina va ku eka hina: “Tekani swakudya swa ndlela, mi ya hlanganisa na vona, mi ku eka vona: ‘Hi malandza ya n’wina, hikwalaho endlani ntwanano na hina;’”’”' },
    { n: 12, text: '“‘leswi swakudya swa hina swi a swi hisa, loko hi humile emakaya ya hina ku ta eka n’wina; kambe sweswi, wasivo, swi omile, swi ri swa ku bola;’”' },
    { n: 13, text: '“‘ni mikwama ya vhinyo leyi, loko hi yi thele, a yi ri yintshwa; kambe wasivo, ya handzuka; ni swiambalo swa hina ni tintangu ta hina swi dyuharile hikwalaho ka ndlela yo leha;’”' },
    { n: 14, text: '“vavanuna va teka swakudya swa vona, va nga vutisanga enon’wini wa Yehovha;”' },
    { n: 15, text: '“Yoxuwa a va endlela ku rhula, a endla ntwanano na vona wa leswaku va ta hanya, naswona tindhuna ta vandla ti va hlambanyela;”' },
    { n: 16, text: '“kutani, endzhaku ka masiku manharhu va endle ntwanano na vona, va twa leswaku va tshama ekusuhi na vona, naswona va tshama exikarhi ka vona;”' },
    { n: 17, text: '“vana va Israyele va ya, va fika emimitini ya vona hi siku ra vunharhu; mimiti ya vona a yi ri Gibiyoni, Kefira, Beroti, ni Kiriati-Yearimi;”' },
    { n: 18, text: '“vana va Israyele a va va dlayanga, hikuva tindhuna ta vandla ti va hlambanyele hi Yehovha Xikwembu xa Israyele; naswona vandla hinkwaro ri tsuvule tindhuna;”' },
    { n: 19, text: '“tindhuna hinkwato ti ku eka vandla hinkwaro: ‘Hi va hlambanyele hi Yehovha Xikwembu xa Israyele, hikwalaho a hi nge va khumbi;’”' },
    { n: 20, text: '“‘leswi hi ta swi endla eka vona: hi ta va tshika va hanya, leswaku vukari byi nga pfukeli hina, hikwalaho ka xihlambanyo lexi hi va hlambanyeleke xona;’”' },
    { n: 21, text: '“tindhuna ti ku eka vona: ‘Va ta hanya, va va vakhuni ni vateki va mati eka vandla hinkwaro,’ hilaha tindhuna ti va byeleke hakona;”' },
    { n: 22, text: '“Yoxuwa a va vitana, a ku eka vona: ‘Hikwalaho ka yini mi hi hembe, mi ku: “Hi le kule na n’wina,” naswona mi tshama exikarhi ka hina?’”' },
    { n: 23, text: '“‘hikwalaho mi rhukeriwe, naswona a ku nge kumiwi eka n’wina lava nga vakhuni ni vateki va mati endhawini ya yindlu ya Xikwembu xa mina;’”' },
    { n: 24, text: '“va hlamula Yoxuwa, va ku: ‘Hikuva swi byeriwe malandza ya wena leswaku Yehovha Xikwembu xa wena xi lerise nandza wa xona Muxe ku mi nyika tiko hinkwaro, ni ku herisa vaaki hinkwavo va tiko mahlweni ka n’wina; hikwalaho hi chave vutomi bya hina swinene hikwalaho ka n’wina, hi endle xileswi;’”' },
    { n: 25, text: '“‘naswona wasivo, hi le vokweni ra wena; hilaha swi nga swinene naswona swi lulameke eka wena ku hi endla hakona, hi endle tano;’”' },
    { n: 26, text: '“va va endla tano, va va ponisa evokweni ra vana va Israyele, va nga va dlayanga;”' },
    { n: 27, text: '“Yoxuwa a va endla vakhuni ni vateki va mati eka vandla, ni le altarini ya Yehovha, ku fika namuntlha, endhawini leyi a nga ta yi hlawula.”' }
  ],
  10: [
    { n: 1, text: '“Kutani, loko Adoni-Zedeke, hosi ya Yerusalema, a twile leswaku Yoxuwa u teke Ayi, a yi herisa, hilaha a endleke hakona eYeriko ni hosi ya yona, a herisa Ayi ni hosi ya yona, ni leswaku vaaki va Gibiyoni va endle ku rhula na Israyele, va tshama exikarhi ka vona;”' },
    { n: 2, text: '“va chava swinene, hikuva Gibiyoni a a ri muti lowukulu, ku fika ni muti wa vuhosi, ni hikuva a wu ri lowukulu ku tlula Ayi, ni vavanuna hinkwavo a va ri lava matimba;”' },
    { n: 3, text: '“hikwalaho Adoni-Zedeke, hosi ya Yerusalema, a rhuma rito eka Ohami, hosi ya Hebroni, ni le ka Piramu, hosi ya Yarmuti, ni le ka Yafiya, hosi ya Lakixi, ni le ka Debiri, hosi ya Egloni, a ku:”' },
    { n: 4, text: '“‘Tlhandlukani mi ta eka mina, mi ndzi pfuna, leswaku hi ba Gibiyoni, hikuva wu endle ku rhula na Yoxuwa ni vana va Israyele;’”' },
    { n: 5, text: '“hikwalaho tihosi ta ntlhanu ta Vamori, hosi ya Yerusalema, hosi ya Hebroni, hosi ya Yarmuti, hosi ya Lakixi, hosi ya Egloni, ti hlengeletana, ti tlhandluka, tona ni mavuthu ya tona hinkwawo, ti ya va ti rhendzela Gibiyoni, ti lwa na wona;”' },
    { n: 6, text: '“vavanuna va Gibiyoni va rhuma rito eka Yoxuwa entsongeni eGilgala, va ku: ‘U nga tshiki voko ra wena eka malandza ya wena; tlhandluka hi ku hatlisa, u ta hi ponisa, u hi pfuna, hikuva tihosi hinkwato ta Vamori, leti ti tshamaka entshaveni, ti hlengeletanile ti lwa na hina;’”' },
    { n: 7, text: '“Yoxuwa a tlhandluka a suka eGilgala, yena ni vanhu hinkwavo lava nga ni matimba, ni vavanuna hinkwavo lava nga ni matimba;”' },
    { n: 8, text: '“Yehovha a ku eka Yoxuwa: ‘U nga va chavi, hikuva ndzi va nyikile evokweni ra wena; a ku na munhu loyi a nga ta yima mahlweni ka wena;’”' },
    { n: 9, text: '“Yoxuwa a ta eka vona hi ku hatlisa, a tlhandluka vusiku hinkwabyo eGilgala;”' },
    { n: 10, text: '“Yehovha a va chavisile mahlweni ka Israyele, va va ba hi ndzilo lowukulu eGibiyoni, va va hlongorisa hi ndlela leyi tlhandlukaka eBet-Oroni, va va ba ku fika eAzeka ni le Makeda;”' },
    { n: 11, text: '“kutani, loko va baleka mahlweni ka Israyele, va ri eku rheleleni ka Bet-Oroni, Yehovha a va hoxa hi maribye lamakulu lawa a ma huma etilweni, ku fika eAzeka, va fa; a va ri votala lava feke hi maribye lawa, ku tlula lava vana va Israyele va va dlayeke hi banga;”' },
    { n: 12, text: '“kutani Yoxuwa a vulavula na Yehovha hi siku leri Yehovha a nyikereke Vamori mahlweni ka vana va Israyele, a ku mahlweni ka Israyele: ‘Dyambu, yima eGibiyoni, na wena, n’weti, enkoveni wa Ayaloni;’”' },
    { n: 13, text: '“kutani dyambu ri yimile, n’weti wu yimile, ku fika loko vanhu va rihanyisa eka valala va vona. Sweswo a swi nga tsariwanga ebukwini ya Jashari? Dyambu ri yimile exikarhi ka matilo, ri nga hatlisanga ku rhelela nkarhi wo ringana ni siku rin’we;”' },
    { n: 14, text: '“naswona a ku ri na siku ro fana na rero, mahlweni ni le ndzhaku ka rona, leri Yehovha a yingiseke rito ra munhu, hikuva Yehovha u lwele Israyele;”' },
    { n: 15, text: '“kutani Yoxuwa a tlhelela, ni Israyele hinkwavo, entsongeni eGilgala;”' },
    { n: 16, text: '“kambe tihosi leti ta ntlhanu ti balekile, ti fika ti fihla ebakweni eMakeda;”' },
    { n: 17, text: '“va byela Yoxuwa va ku: ‘Tihosi ta ntlhanu ti kumekile, ti fihle ebakweni eMakeda;’”' },
    { n: 18, text: '“Yoxuwa a ku: ‘Gingani maribye lamakulu enyangweni wa bako, mi veka vavanuna va ku va rindza;’”' },
    { n: 19, text: '“‘naswona n’wina, mi nga yimi, hlongorisani valala va n’wina, mi ba lava va ha rhangeriweke, mi nga va pfumeleli ku nghena emimitini ya vona, hikuva Yehovha Xikwembu xa n’wina u va nyikile evokweni ra n’wina;’”' },
    { n: 20, text: '“kutani, loko Yoxuwa ni vana va Israyele va hete ku va dlaya hi ku hluriwa lokukulu, va va herisa, ni lava va seleke va nghene emimitini ya vuhosi;”' },
    { n: 21, text: '“vanhu hinkwavo va tlhelela eka Yoxuwa entsongeni eMakeda, va ri lava nga riki na nandzu; a ku na munhu loyi a tlhaveke ririmi ra yena eka vana va Israyele;”' },
    { n: 22, text: '“Yoxuwa a ku: ‘Pfulekani nyangwa wa bako, mi humesa tihosi leti ta ntlhanu ebakweni, mi ti tisa eka mina;’”' },
    { n: 23, text: '“va endla tano, va humesa tihosi leti ta ntlhanu ebakweni, hosi ya Yerusalema, hosi ya Hebroni, hosi ya Yarmuti, hosi ya Lakixi, hosi ya Egloni;”' },
    { n: 24, text: '“loko va humese tihosi leti eka Yoxuwa, Yoxuwa a vitana vavanuna hinkwavo va Israyele, a ku eka tindhuna ta vavanuna lava va nga ya na yena: ‘Tshinelani, mi veka milenge ya n’wina ehenhla ka tinhloko ta tihosi leti.’ Va tshinela, va veka milenge ya vona ehenhla ka tinhloko ta vona;”' },
    { n: 25, text: '“Yoxuwa a ku eka vona: ‘Mi nga chavi, mi nga rhurhumeli; tiyisani, mi va ni xivindzi, hikuva Yehovha u ta endla tano eka valala hinkwavo lava mi lwelaka na vona;’”' },
    { n: 26, text: '“endzhaku ka sweswo Yoxuwa a va ba, a va dlaya, a va hayeka emunxini lowu, va hayekiwa emunxini ku fika nimadyambu;”' },
    { n: 27, text: '“kutani nimadyambu Yoxuwa a lerisa leswaku va va susa emunxini, va va cukumeta ebakweni leri va fihleke eka rona, va hlayela maribye lamakulu enyangweni wa bako, wu kona ku fika namuntlha;”' },
    { n: 28, text: '“Yoxuwa a teka Makeda hi siku rero, a ba hosi ya yona hi banga, a va herisa, yena ni hinkwavo lava a va ri na yena, a nga tshikanga munhu a hanya; a endla eka hosi ya Makeda hilaha a endleke hakona eka hosi ya Yeriko;”' },
    { n: 29, text: '“Yoxuwa a huma, ni Israyele hinkwavo, eMakeda, va ya eLibna, va lwa na Libna;”' },
    { n: 30, text: '“Yehovha a nyiketa Libna ni hosi ya yona evokweni ra Israyele, va yi ba hi banga, ni hinkwavo lava a va ri eka yona, va nga tshiki munhu a hanya; a endla eka hosi ya yona hilaha a endleke hakona eka hosi ya Yeriko;”' },
    { n: 31, text: '“Yoxuwa a huma, ni Israyele hinkwavo, eLibna, va ya eLakixi, va rhendzela muti, va lwa na wona;”' },
    { n: 32, text: '“Yehovha a nyiketa Lakixi evokweni ra Israyele, va yi teka hi siku ra vumbirhi, va yi ba hi banga, ni hinkwavo lava a va ri eka yona, hilaha va endleke hakona eka Libna;”' },
    { n: 33, text: '“kutani Horamu, hosi ya Gezeri, a tlhandluka a ta pfuna Lakixi; Yoxuwa a n’wi ba, ni vanhu va yena, va nga tshiki munhu a hanya;”' },
    { n: 34, text: '“Yoxuwa a huma, ni Israyele hinkwavo, eLakixi, va ya eEgloni, va rhendzela muti, va lwa na wona;”' },
    { n: 35, text: '“va wu teka hi siku rero, va wu ba hi banga, ni hinkwavo lava a va ri eka yona, va va herisa hi siku rero, hilaha va endleke hakona eka Lakixi;”' },
    { n: 36, text: '“Yoxuwa a tlhandluka, ni Israyele hinkwavo, eEgloni, va ya eHebroni, va lwa na wona;”' },
    { n: 37, text: '“va wu teka, va ba hosi ya wona hi banga, ni mimiti hinkwayo ya wona, ni hinkwavo lava a va ri eka wona, va nga tshiki munhu a hanya, hilaha va endleke hakona eka Egloni; va wu herisa ni hinkwavo lava a va ri eka wona;”' },
    { n: 38, text: '“Yoxuwa a tlhelela, ni Israyele hinkwavo, eDebiri, va lwa na wona;”' },
    { n: 39, text: '“va wu teka, ni hosi ya wona, ni mimiti hinkwayo ya wona, va va ba hi banga, va herisa hinkwavo lava a va ri eka wona, va nga tshiki munhu a hanya; hilaha va endleke hakona eka Hebroni, hilaha va endleke hakona eka Libna ni hosi ya yona;”' },
    { n: 40, text: '“Yoxuwa a teka tiko hinkwaro, tintshava, ni tiko ra le dzongeni, ni tihova, ni tindhawu leti nga ehenhla ka tintshava, ni tihosi hinkwato ta tona, va nga tshiki munhu a hanya, va herisa hinkwavo lava nga ni moya, hilaha Yehovha Xikwembu xa Israyele a leriseke hakona;”' },
    { n: 39, text: '“Yoxuwa a va ba ku sukela eKadeshi-Barneya ku fika eGaza, ni tiko hinkwaro ra Goxeni, ku fika eGibiyoni;”' },
    { n: 42, text: '“Yoxuwa a teka tihosi leti hinkwato ni tiko ra tona hi nkarhi wun’we, hikuva Yehovha Xikwembu xa Israyele a lwele Israyele;”' },
    { n: 43, text: '“Yoxuwa a tlhelela, ni Israyele hinkwavo, entsongeni eGilgala.”' }
  ],
  11: [
    { n: 1, text: '“Kutani, loko Yabini, hosi ya Hasoro, a twile swilo leswi, a rhuma rito eka Yobabu, hosi ya Madoni, ni le ka hosi ya Ximroni, ni le ka hosi ya Akixafa;”' },
    { n: 2, text: '“ni le ka tihosi leti a ti ri entshaveni, ni le tlhelo ra le dzongeni wa Kinereti, ni le tihoveni, ni le matikweni ya le kusuhi ni Doro, hi tlhelo ra le vuxeni;”' },
    { n: 3, text: '“Vakanana hi tlhelo ra le vuxeni ni le tlhelo ra le vupela-dyambu, Vamori, Vahiti, Vaperizi, Vayebusi entshaveni, ni Vahivhi lava a va ri ehansi ka Hermoni etikweni ra Mispa;”' },
    { n: 4, text: '“va huma, tona ni mavuthu ya tona hinkwawo, vanhu vo tala ku fana ni sava leri nga eribyeni ra lwandle, ni tihanci to tala, ni tikalaki;”' },
    { n: 5, text: '“tihosi leti hinkwato ti hlengeletana, ti ta, ti ya tshamela eMiva ya Meromi, leswaku ti lwa na Israyele;”' },
    { n: 6, text: '“Yehovha a ku eka Yoxuwa: ‘U nga va chavi, hikuva mundzuku hi nkarhi lowu, ndzi ta va nyiketa hinkwavo va dlayiwe mahlweni ka Israyele; u ta tsemula tihanci ta vona, u hisa tikalaki ta vona hi ndzilo;’”' },
    { n: 7, text: '“Yoxuwa a ta, ni vanhu hinkwavo lava nga ni matimba, eMiva ya Meromi, a va hlasela hi ku hatlisa;”' },
    { n: 8, text: '“Yehovha a va nyiketa evokweni ra Israyele, va va ba, va va hlongorisa ku fika eSidoni Lonkulu, ni le Misrefoti-Mayimi, ni le tlhelo ra Mispa, hi tlhelo ra le vuxeni; va va ba, va nga tshiki munhu a hanya;”' },
    { n: 9, text: '“Yoxuwa a endla eka vona hilaha Yehovha a n’wi leriseke hakona; a tsemula tihanci ta vona, a hisa tikalaki ta vona hi ndzilo;”' },
    { n: 10, text: '“Yoxuwa a tlhelela hi nkarhi wolowo, a teka Hasoro, a ba hosi ya yona hi banga; hikuva Hasoro eku sunguleni a yi ri nhloko ya mimiti leyi hinkwayo;”' },
    { n: 11, text: '“va ba moya hinkwawo lowu a wu ri eka yona hi banga, va va herisa, a ku salanga nchumu lowu nga ni moya; a hisa Hasoro hi ndzilo;”' },
    { n: 12, text: '“Yoxuwa a teka mimiti hinkwayo ya tihosi letiya, ni tihosi hinkwato ta tona, a va ba hi banga, a va herisa, hilaha Muxe, nandza wa Yehovha, a leriseke hakona;”' },
    { n: 13, text: '“kambe mimiti hinkwayo leyi a yi yimile etintshaveni, Israyele a nga yi hisanga; ntsena Hasoro, yona ntsena Yoxuwa a yi hisile;”' },
    { n: 14, text: '“naswona vana va Israyele va teke nyiko hinkwayo ya mimiti leyi, ni swifuwo, tanihi ndzhaka ya vona; kambe vavanuna hinkwavo va va ba hi banga, ku fika loko va va herisa, a va tshikanga munhu a hanya;”' },
    { n: 15, text: '“hilaha Yehovha a leriseke Muxe, nandza wa yena, hakona, Muxe a lerisa Yoxuwa, naswona Yoxuwa a endla tano; a nga tshikanga nchumu eka hinkwaswo leswi Yehovha a leriseke Muxe hakona;”' },
    { n: 16, text: '“Yoxuwa a teka tiko hinkwaro, tintshava, ni tiko hinkwaro ra le dzongeni, ni tiko hinkwaro ra Goxeni, ni tihova, ni Araba, ni tintshava ta Israyele, ni tihova ta tona;”' },
    { n: 17, text: '“ku sukela entshaveni ya Halaka, leyi tlhandlukaka eSeyiri, ku fika eBali-Gadi, entshaveni ya Hermoni, ehansi ka ntshava ya Hermoni; a teka tihosi hinkwato ta tona, a va ba, a va dlaya;”' },
    { n: 18, text: '“Yoxuwa u lwe tinyimpi to tala ni tihosi toleto hinkwato;”' },
    { n: 19, text: '“a ku na muti lowu wu endleke ku rhula ni vana va Israyele, handle ka Vahivhi, vaaki va Gibiyoni; hinkwavo va va teke hi nyimpi;”' },
    { n: 20, text: '“hikuva a swi huma eka Yehovha ku tiyisa timbilu ta vona, leswaku va ta lwa na Israyele, leswaku a va herisa, va nga kumi tintswalo, kambe va va herisa, hilaha Yehovha a leriseke Muxe hakona;”' },
    { n: 21, text: '“Yoxuwa a ta hi nkarhi wolowo, a herisa Vaanaki entshaveni, eHebroni, eDebiri, eAnabi, entshaveni hinkwayo ya Yuda, ni le tintshaveni hinkwato ta Israyele; Yoxuwa a va herisa ni mimiti ya vona;”' },
    { n: 22, text: '“a ku salanga Vaanaki etikweni ra vana va Israyele; ntsena eGaza, eGati, ni le Axidodi, va sale;”' },
    { n: 23, text: '“Yoxuwa a teka tiko hinkwaro, hilaha Yehovha a byeleke Muxe hakona; Yoxuwa a ri nyika Israyele ku ri ndzhaka, hi ku ya hi tinyimba ta vona. Kutani tiko ri tshama ri ri ni ku rhula eka tinyimpi.”' }
  ],
  12: [
    { n: 1, text: '“Leti i tihosi ta tiko leti vana va Israyele va ti dlayeke, va teka tiko ra tona eYordani, hi tlhelo ra le vuxeni, ku sukela emupfhukeni wa Aroni ku fika entshaveni ya Hermoni, ni tiko hinkwaro ra Araba, hi tlhelo ra le vuxeni;”' },
    { n: 2, text: '“Sihoni, hosi ya Vamori, loyi a a tshama eXesiboni, a fumela ku sukela eAroeri, leyi nga etlhelo ka nambu wa Aroni, ni le xikarhi ka nambu, ni hafu ya Giliyadi, ku fika enambyeni wa Yaboki, ndzilakano wa vana va Amoni;”' },
    { n: 3, text: '“ni Araba ku fika elwandle ra Kinereti, hi tlhelo ra le vuxeni, ku fika elwandle ra Araba, Lwandle ra Munyu, hi tlhelo ra le vuxeni, hi ndlela ya Beti-Yeshimoti; ni le dzongeni, ehansi ka tintshava ta Pisiga;”' },
    { n: 4, text: '“ni ndzilakano wa Ogi, hosi ya Baxani, loyi a a ri wa nsindza wa Varefayi, loyi a a tshama eAxtaroti ni le Edrehi;”' },
    { n: 5, text: '“a fumela entshaveni ya Hermoni, ni le Saleka, ni Baxani hinkwaro, ku fika endzilakanweni wa Vageshuri ni Va-Maakati, ni hafu ya Giliyadi, ndzilakano wa Sihoni, hosi ya Xesiboni;”' },
    { n: 6, text: '“Muxe, nandza wa Yehovha, ni vana va Israyele va va dlayile; Muxe, nandza wa Yehovha, a ri nyika Ruvene, Gadi, ni hafu ya rixaka ra Manase ku ri ndzhaka;”' },
    { n: 7, text: '“leti i tihosi ta tiko leti Yoxuwa ni vana va Israyele va ti dlayeke eYordani, hi tlhelo ra le vupela-dyambu, ku sukela eBali-Gadi, enkoveni wa Lebanoni, ku fika entshaveni ya Halaka, leyi tlhandlukaka eSeyiri; Yoxuwa a ri nyika tinyimba ta Israyele ku ri ndzhaka, hi ku ya hi ntsengo wa vona;”' },
    { n: 8, text: '“entshaveni, ni le tihoveni, ni le matikweni ya le kusuhi ni lwandle, ni le tihoveni, ni emananga, ni le dzongeni; Vahiti, Vamori, Vakanana, Vaperizi, Vahivhi, ni Vayebusi;”' },
    { n: 9, text: '“hosi ya Yeriko, yin’we; hosi ya Ayi, leyi nga etlhelo ka Betheni, yin’we;”' },
    { n: 10, text: '“hosi ya Yerusalema, yin’we; hosi ya Hebroni, yin’we;”' },
    { n: 11, text: '“hosi ya Yarmuti, yin’we; hosi ya Lakixi, yin’we;”' },
    { n: 12, text: '“hosi ya Egloni, yin’we; hosi ya Gezeri, yin’we;”' },
    { n: 13, text: '“hosi ya Debiri, yin’we; hosi ya Gederi, yin’we;”' },
    { n: 14, text: '“hosi ya Harma, yin’we; hosi ya Aradi, yin’we;”' },
    { n: 15, text: '“hosi ya Libna, yin’we; hosi ya Adulamu, yin’we;”' },
    { n: 16, text: '“hosi ya Makeda, yin’we; hosi ya Betheni, yin’we;”' },
    { n: 17, text: '“hosi ya Tapuwa, yin’we; hosi ya Heferi, yin’we;”' },
    { n: 18, text: '“hosi ya Afeka, yin’we; hosi ya Laxaroni, yin’we;”' },
    { n: 19, text: '“hosi ya Madoni, yin’we; hosi ya Hasoro, yin’we;”' },
    { n: 20, text: '“hosi ya Ximroni-Meroni, yin’we; hosi ya Akixafa, yin’we;”' },
    { n: 21, text: '“hosi ya Taanaki, yin’we; hosi ya Megido, yin’we;”' },
    { n: 22, text: '“hosi ya Kedexi, yin’we; hosi ya Yokneami, ya Karmeli, yin’we;”' },
    { n: 23, text: '“hosi ya Doro, leyi nga etlhelo ka lwandle, yin’we; hosi ya Goyimi, ya Gilgala, yin’we;”' },
    { n: 24, text: '“hosi ya Tirsa, yin’we; tihosi hinkwato leti ti ri khume na mune-ntse-ntse.”' }
  ],
  13: [
    { n: 1, text: '“Kutani Yoxuwa a a dyuharile, a kule swinene; Yehovha a ku eka yena: ‘U dyuharile, u kule swinene, naswona ku sale tiko ro tala leri nga tekeriwangiki;’”' },
    { n: 2, text: '“‘leri i tiko leri saleke: mindzilakano hinkwayo ya Vafilisita, ni Vageshuri hinkwavo;’”' },
    { n: 3, text: '“‘ku sukela eXihore, leyi nga mahlweni ka Egipta, ku fika endzilakanweni wa Ekroni, hi tlhelo ra le n’walungwini, leyi hlayiwaka tanihi ya Vakanana; tihosi ta ntlhanu ta Vafilisita: va Gazani, va Axidodi, va Axikeloni, va Gitani, ni va Ekroni; ni Vaavhi;’”' },
    { n: 4, text: '“‘hi tlhelo ra le dzongeni, tiko hinkwaro ra Vakanana, ni Meara, leyi nga ya Vasidoni, ku fika eAfeka, ku fika endzilakanweni wa Vamori;’”' },
    { n: 5, text: '“‘ni tiko ra Vagebali, ni Lebanoni hinkwaro, hi tlhelo ra le vuxeni, ku sukela eBali-Gadi ehansi ka ntshava ya Hermoni ku fika endzilakanweni wa Hamati;’”' },
    { n: 6, text: '“‘hinkwavo vaaki va tintshava, ku sukela eLebanoni ku fika eMisrefoti-Mayimi, hinkwavo Vasidoni; mina ndzi ta va hlongola mahlweni ka vana va Israyele; kambe wena, u ta ri avelana na Israyele hi mpfhuka, hilaha ndzi ku leriseke hakona;’”' },
    { n: 7, text: '“‘hikwalaho, avelana tiko leri ku ri ndzhaka eka tinyimba ta khume na tinfi, ni hafu ya rixaka ra Manase;’”' },
    { n: 8, text: '“‘na Ruvene, na Gadi va teke ndzhaka ya vona, leyi Muxe a va nyikeke yona, hi tlhelo ra le vuxeni ka Yordani, hilaha Muxe, nandza wa Yehovha, a va nyikeke hakona;’”' },
    { n: 9, text: '“‘ku sukela eAroeri, leyi nga etlhelo ka nambu wa Aroni, ni muti lowu nga exikarhi ka nambu, ni tiko hinkwaro ra Medeba ku fika eDiboni;’”' },
    { n: 10, text: '“‘ni mimiti hinkwayo ya Sihoni, hosi ya Vamori, loyi a a tshama eXesiboni, ku fika endzilakanweni wa vana va Amoni;’”' },
    { n: 11, text: '“‘ni Giliyadi, ni ndzilakano wa Vageshuri ni Va-Maakati, ni ntshava hinkwayo ya Hermoni, ni Baxani hinkwaro ku fika eSaleka;’”' },
    { n: 12, text: '“‘ni vuhosi hinkwaro bya Ogi, wa Baxani, loyi a a fumela eAxtaroti ni le Edrehi, loyi a a ri wa nsindza wa Varefayi; Muxe a va ba, a va hlongola;’”' },
    { n: 13, text: '“‘kambe vana va Israyele a va va hlongolanga Vageshuri ni Va-Maakati; kambe Vageshuri ni Va-Maakati va tshame exikarhi ka Israyele ku fika namuntlha;’”' },
    { n: 14, text: '“‘kambe ndzhaka ya rixaka ra Levhi a nga va nyikangiki yona; magandzelo ya Yehovha Xikwembu xa Israyele hi ndzilo, i ndzhaka ya vona, hilaha a va byeleke hakona;’”' },
    { n: 15, text: '“‘Muxe a nyika rixaka ra vana va Ruvene ndzhaka hi ku ya hi mindyangu ya vona;’”' },
    { n: 16, text: '“‘ndzilakano wa vona wu sukela eAroeri, leyi nga etlhelo ka nambu wa Aroni, ni muti lowu nga exikarhi ka nambu, ni tiko hinkwaro ra Medeba;’”' },
    { n: 17, text: '“‘Xesiboni ni mimiti hinkwayo ya rona leyi nga etihoveni, Diboni, Bamoti-Bali, Beti-Baal-Meoni;’”' },
    { n: 18, text: '“‘Yaza, Kedemoti, Mefati;’”' },
    { n: 19, text: '“‘Kiriatayimi, Sibma, Zereti-Xahari, entshaveni ya nkova;’”' },
    { n: 20, text: '“‘Beti-Peori, ni tintshava ta Pisiga, Beti-Yeshimoti;’”' },
    { n: 21, text: '“‘ni mimiti hinkwayo ya tihova, ni vuhosi hinkwaro bya Sihoni, hosi ya Vamori, loyi a a tshama eXesiboni, loyi Muxe a n’wi dlayeke, ni tihosi ta Midiyani, Evi, Rekemu, Zur, Huri, ni Reba, tihosi ta Sihoni, leti ti tshamaka etikweni;’”' },
    { n: 22, text: '“‘Balamu, n’wana wa Beori, loyi a a ri muprofeta, vana va Israyele va n’wi dlaye hi banga, ni vambirhi va vona;’”' },
    { n: 23, text: '“‘ndzilakano wa vana va Ruvene a ku ri Yordani; leyi i ndzhaka ya vana va Ruvene, hi ku ya hi mindyangu ya vona, mimiti ya vona ni le matlhelo ya vona;’”' },
    { n: 24, text: '“‘Muxe a nyika rixaka ra Gadi ndzhaka hi ku ya hi mindyangu ya vona;’”' },
    { n: 25, text: '“‘ndzilakano wa vona a ku ri Yazeri, ni mimiti hinkwayo ya Giliyadi, ni hafu ya tiko ra vana va Amoni, ku fika eAroeri, leyi nga mahlweni ka Raba;’”' },
    { n: 26, text: '“‘ku sukela eXesiboni ku fika eRamati-Mispa ni Betoni, ni ku sukela eMahanayimi ku fika endzilakanweni wa Debiri;’”' },
    { n: 27, text: '“‘ni le nkoveni, Beti-Arani, Beti-Nimra, Sukoti, ni Zafoni, ndzilakano wa vuhosi bya Sihoni, hosi ya Xesiboni, Yordani ni matlhelo ya wona ku fika elwandle ra Kinereti, hi tlhelo ra le vuxeni ka Yordani;’”' },
    { n: 28, text: '“‘leyi i ndzhaka ya vana va Gadi, hi ku ya hi mindyangu ya vona, mimiti ya vona ni le matlhelo ya vona;’”' },
    { n: 29, text: '“‘Muxe a nyika rixaka ra Manase ndzhaka hi ku ya hi mindyangu ya vona;’”' },
    { n: 30, text: '“‘ndzilakano wa vona wu sukela eMahanayimi, Baxani hinkwaro, vuhosi hinkwaro bya Ogi, hosi ya Baxani, ni mimiti hinkwayo ya Yayiri, leyi nga eBaxani, ntlhanu wa madzana na ntlhanu wa mimiti;’”' },
    { n: 31, text: '“‘ni hafu ya Giliyadi, ni Axtaroti, ni Edrehi, mimiti ya vuhosi bya Ogi, eBaxani, a swi va vana va Makiri, n’wana wa Manase, ni vana va Makiri hi ku ya hi mindyangu ya vona;’”' },
    { n: 32, text: '“‘leti i ndzhaka leti Muxe a ti nyikeke etiphaleni ta Mowabu, hi tlhelo ra le vuxeni ka Yordani, hi tlhelo ra le vuxeni ka Yeriko;’”' },
    { n: 33, text: '“‘kambe ndzhaka ya rixaka ra Levhi a nga va nyikangiki yona; Yehovha Xikwembu xa Israyele hi yena ndzhaka ya vona, hilaha a va byeleke hakona.’”' }
  ],
  14: [
    { n: 1, text: '“Leti i tindhawu leti vana va Israyele va ti tekeke tanihi ndzhaka etikweni ra Kanana, leti Eleazari, muprista, na Yoxuwa, n’wana wa Nuni, ni tindhuna ta mindyangu ya tinyimba ta vana va Israyele, va va nyikeke tona;”' },
    { n: 2, text: '“va avelane hi mpfhuka, hilaha Yehovha a leriseke Muxe, hi ta tinyimba ta khume na tinfi, ni rixaka ra khume na mambirhi;”' },
    { n: 3, text: '“hikuva Muxe a nyike tinyimba timbirhi ni hafu ya rixaka ndzhaka hi tlhelo ra le vuxeni ka Yordani; kambe Valevhi a nga va nyikanga ndzhaka exikarhi ka vona;”' },
    { n: 4, text: '“hikuva vana va Yosefa a va ri tinyimba timbirhi, Manase na Efrayimi; naswona a va nga nyikanga Valevhi ndzhaka etikweni, ntsena miti yo tshama eka yona, ni malangavi ya vona ya swifuwo swa vona;”' },
    { n: 5, text: '“hilaha Yehovha a leriseke Muxe hakona, vana va Israyele va endle tano, va avelana tiko;”' },
    { n: 6, text: '“kutani vana va Yuda va ta eka Yoxuwa eGilgala, naswona Kalebi, n’wana wa Yefune, wa Muzenizi, a ku eka yena: ‘U tiva rito leri Yehovha a ri byeleke Muxe, munhu wa Xikwembu, mayelana ni mina ni wena eKadeshi-Barneya;’”' },
    { n: 7, text: '“‘ndzi ri ni malembe ya khume na mune loko Muxe, nandza wa Yehovha, a ndzi rhumele eKadeshi-Barneya, leswaku ndzi ya languta tiko; naswona ndzi n’wi tisele rito hilaha a a ri na rona embilwini ya mina;’”' },
    { n: 8, text: '“‘kambe vamakwerhu lava va tlhandlukeke na mina va helise timbilu ta vanhu; kambe mina ndzi landzele Yehovha Xikwembu xa mina hi mbilu ya mina hinkwayo;’”' },
    { n: 9, text: '“‘Muxe a hlambanya hi siku rero a ku: “Tiko leri nenge wa wena wu nga ta kandziya ehenhla ka rona ri ta va ndzhaka ya wena, ni ya vana va wena hilaha ku nga heriki, hikuva u landzele Yehovha Xikwembu xa wena hi mbilu ya wena hinkwayo;”’”' },
    { n: 10, text: '“‘naswona wasivo, Yehovha u ndzi hlayisile, hilaha a vuleke hakona, malembe lawa ya khume na mune-ntse-mune, ku sukela loko Yehovha a vule rito leri eka Muxe, loko Israyele a famba emananga; naswona wasivo, ndzi ni malembe ya nhungu-ntse-mune namuntlha;’”' },
    { n: 11, text: '“‘ndzi ha ri na matimba namuntlha, hilaha ndzi a ri na matimba ha wona hi siku leri Muxe a ndzi rhumeleke ha rona; hilaha matimba ya mina a ma ri hakona enkarhini wolowo, ma ha ri tano namuntlha, ku lwa ni ku huma ni ku nghena;’”' },
    { n: 12, text: '“‘hikwalaho, ndzi nyika ntshava leyi Yehovha a vuleke hi yona hi siku rero; hikuva u twile hi siku rero leswaku Va-Anaki va kona, ni mimiti leyi nga ni khokho lerikulu, leyi nga ni matimba; kumbexana Yehovha u ta va na mina, ndzi ta va hlongola hilaha Yehovha a vuleke hakona;’”' },
    { n: 13, text: '“Yoxuwa a n’wi katekisa, a nyika Kalebi, n’wana wa Yefune, Hebroni ku ri ndzhaka;”' },
    { n: 14, text: '“hikwalaho Hebroni a va ndzhaka ya Kalebi, n’wana wa Yefune, wa Muzenizi, ku fika namuntlha, hikuva u landzele Yehovha Xikwembu xa Israyele hi mbilu ya yena hinkwayo;”' },
    { n: 15, text: '“naswona vito ra Hebroni eku sunguleni a ku ri Kiriyati-Arba, loyi a a ri munhu lonkulu exikarhi ka Va-Anaki; kutani tiko ri tshama ri ri ni ku rhula eka tinyimpi.”' }
  ],
  16: [
    { n: 1, text: '“Mpfhuka wa vana va Yosefa wu sungule eYordani, etlhelo ka mati ya Yeriko, hi vuxa bya mati ya Yeriko, emananga lawa ma tlhandlukaka ku suka eYeriko ma ya entshaveni ya Betheni;”' },
    { n: 2, text: '“wu huma eBetheni ku ya eLuzi, wu hundza endzilakanweni wa Varkia eAtaroti;”' },
    { n: 3, text: '“wu rhelela hi vupela-dyambu endzilakanweni wa Vayafleti, ku fika endzilakanweni wa Bet-Oroni ya le hansi, ku fika eGezeri, wu hela elwandle;”' },
    { n: 4, text: '“vana va Yosefa, Manase na Efrayimi, va teke ndzhaka ya vona;”' },
    { n: 5, text: '“ndzilakano wa vana va Efrayimi, hi ku ya hi mindyangu ya vona, wu ri: ndzilakano wa ndzhaka ya vona hi vuxa i Atarot-Adari, ku fika eBet-Oroni ya le henhla;”' },
    { n: 6, text: '“wu huma endzilakanweni wu ya elwandle eMikmetati hi n’walungu, wu rhendzeleka hi vuxa ku ya eTaanati-Xilo, wu wu hundza hi vuxa bya Yanoha;”' },
    { n: 7, text: '“wu rhelela ku suka eYanoha ku ya eAtaroti ni le Naarata, wu khumba Yeriko, wu hela eYordani;”' },
    { n: 8, text: '“wu huma eTapuwa hi vupela-dyambu ku ya eNkoveni wa Kana, wu hela elwandle. Leyi i ndzhaka ya rixaka ra vana va Efrayimi, hi ku ya hi mindyangu ya vona;”' },
    { n: 9, text: '“naswona mimiti leyi a yi hambanisiweke ni vana va Efrayimi exikarhi ka ndzhaka ya vana va Manase, mimiti hinkwayo ni matlhelo ya yona;”' },
    { n: 10, text: '“a va va hlongolanga Vakanana lava tshamaka eGezeri; kutani Vakanana va tshame exikarhi ka Efrayimi ku fika namuntlha, va va malandza va ku tirha.”' }
  ],
  17: [
    { n: 1, text: '“Kutani mpfhuka wu ve eka rixaka ra Manase, hikuva yena i mativula ya Yosefa: Makiri, mativula ya Manase, tata wa Giliyadi, hikuva a a ri munhu wa nyimpi, a teka Giliyadi na Baxani;”' },
    { n: 2, text: '“naswona a ku ri mpfhuka eka vana va Manase lava seleke, hi ku ya hi mindyangu ya vona; eka vana va Abiyazeri, eka vana va Heleki, eka vana va Asriyeli, eka vana va Xekemi, eka vana va Heferi, eka vana va Xemida; lava i vana va xinuna va Manase, n’wana wa Yosefa, hi ku ya hi mindyangu ya vona;”' },
    { n: 3, text: '“kambe Zelofehadi, n’wana wa Heferi, n’wana wa Giliyadi, n’wana wa Makiri, n’wana wa Manase, a a nga ri na vana va xinuna, ntsena vana va xisati; naswona mavito ya vana va xisati a ku ri Mahla, Noa, Hogla, Milka, ni Tirza;”' },
    { n: 4, text: '“va tshinela mahlweni ka Eleazari, muprista, ni mahlweni ka Yoxuwa, n’wana wa Nuni, ni mahlweni ka tindhuna, va ku: ‘Yehovha u lerise Muxe leswaku a hi nyika ndzhaka exikarhi ka vamakwerhu.’ Kutani va va nyika ndzhaka exikarhi ka vamakwerhu va tatana wa vona, hilaha Yehovha a leriseke hakona;”' },
    { n: 5, text: '“kutani Manase a kuma swiphemu swa khume, handle ka tiko ra Giliyadi na Baxani, leri nga hi vuxa ka Yordani;”' },
    { n: 6, text: '“hikuva vana va xisati va Manase va teke ndzhaka exikarhi ka vana va yena; naswona tiko ra Giliyadi ri ve ra vana va Manase lava seleke;”' },
    { n: 7, text: '“ndzilakano wa Manase wu sukela eAseri ku fika eMikmetati, leyi nga mahlweni ka Xikemi; ndzilakano wu ya hi vuxa ku fika eka vaaki va En-Tapuwa;”' },
    { n: 8, text: '“tiko ra Tapuwa a ku ri ra Manase, kambe Tapuwa, endzilakanweni wa Manase, a ku ri ra vana va Efrayimi;”' },
    { n: 9, text: '“ndzilakano wu rhelela eNkoveni wa Kana, hi n’walungu wa nkova; mimiti leyi ya Efrayimi yi le xikarhi ka mimiti ya Manase, ndzilakano wa Manase wu le n’walungwini wa nkova, wu hela elwandle;”' },
    { n: 10, text: '“Efrayimi a ku ri hi dzonga, Manase a ku ri hi n’walungu, naswona lwandle i ndzilakano wa vona; va khumba Aseri hi n’walungu, na Isakari hi vuxa;”' },
    { n: 11, text: '“Manase a a ri na mimiti eka Isakari ni le ka Aseri: Beti-Xani ni matlhelo ya yona, Ibleami ni matlhelo ya yona, vaaki va Doro ni matlhelo ya yona, vaaki va En-Doro ni matlhelo ya yona, vaaki va Taanaki ni matlhelo ya yona, vaaki va Megido ni matlhelo ya yona, nharhu wa matlhelo;”' },
    { n: 12, text: '“kambe vana va Manase a va swi kotanga ku teka mimiti leyi; kutani Vakanana va ringeta ku tshama etikweni rero;”' },
    { n: 13, text: '“kutani, loko vana va Israyele va tiyile, va endla Vakanana va va malandza, kambe a va va hlongolanga hi ku hetiseka;”' },
    { n: 14, text: '“kutani vana va Yosefa va byela Yoxuwa, va ku: ‘Hikwalaho ka yini u ndzi nyike mpfhuka wun’we ni xiphemu xin’we, kasi ndzi tiko lerikulu, hikuva Yehovha u ndzi katekisile ku fikela sweswi?’”' },
    { n: 15, text: '“Yoxuwa a ku eka vona: ‘Loko mi ri tiko lerikulu, tlhandlukani mi ya eskhokhweni, mi titemela kwalaho etikweni ra Vaperizi ni ra Varefayi, hikuva ntshava ya Efrayimi yi mi ntsongo;’”' },
    { n: 16, text: '“kutani vana va Yosefa va ku: ‘Ntshava a yi nge hi ringani; naswona Vakanana hinkwavo lava tshamaka etikweni ra nkova va na makalaki ya nsuku, hinkwavo lava nga eBeti-Xani ni matlhelo ya yona, ni lava nga enkoveni wa Yezereyeli;’”' },
    { n: 17, text: '“Yoxuwa a byela yindlu ya Yosefa, eEfrayimi na Manase, a ku: ‘Mi tiko lerikulu, naswona mi na matimba lamakulu; a mi nge vi na mpfhuka wun’we;’”' },
    { n: 18, text: '“‘kambe ntshava yi ta va ya n’wina; hikuva i skhokho, mi ta xi tsema, naswona masungulo ya xona ya ta va ya n’wina; hikuva mi ta hlongola Vakanana, hambiloko va ri na makalaki ya nsuku, naswona va ri va matimba.’”' }
  ],
  18: [
    { n: 1, text: '“Kutani vandla hinkwaro ra vana va Israyele ri hlengeletana eXilo, ri veka tende ra ntsombano kwalaho; naswona tiko a ri hluriwe mahlweni ka vona;”' },
    { n: 2, text: '“ku sale tinyimba ta nkombo exikarhi ka vana va Israyele, leti a ti nga si teka ndzhaka ya tona;”' },
    { n: 3, text: '“Yoxuwa a ku eka vana va Israyele: ‘Mi ta hlwela ku ya teka ndzhaka leyi Yehovha Xikwembu xa vatata wa n’wina a mi nyikeke yona?’”' },
    { n: 4, text: '“‘ti hlawuleleni vavanuna vanharhu eka rixaka rin’we-rin’we, ndzi ta va rhuma, va suka va famba etikweni, va ri tsala hi ku ya hi ndzhaka ya vona, va tlhelela eka mina;’”' },
    { n: 5, text: '“‘va ri avanyisa hi swiphemu swa nkombo; Yuda u ta tshama endzilakanweni wa yena hi dzonga, naswona vana va Yosefa va ta tshama endzilakanweni wa vona hi n’walungu;’”' },
    { n: 6, text: '“‘naswona n’wina mi ta tsala tiko hi swiphemu swa nkombo, mi swi tisa eka mina laha; ndzi ta mi hoxelana mpfhuka laha mahlweni ka Yehovha Xikwembu xa hina;’”' },
    { n: 7, text: '“‘hikuva Valevhi a va na swiphemu exikarhi ka n’wina, hikuva vuprista bya Yehovha i ndzhaka ya vona; naswona Ruvene, Gadi, ni hafu ya rixaka ra Manase va teke ndzhaka ya vona hi vuxa ka Yordani, leyi Muxe, nandza wa Yehovha, a va nyikeke yona;’”' },
    { n: 8, text: '“vavanuna va pfuka, va famba; Yoxuwa a lerisa lava va fambaka ku ya tsala tiko, a ku: ‘Yanani, mi famba etikweni, mi ri tsala, mi tlhelela eka mina, naswona ndzi ta mi hoxelana mpfhuka laha eXilo, mahlweni ka Yehovha;’”' },
    { n: 9, text: '“vavanuna va famba, va tsemakanya tiko, va ri tsala hi mimiti hi swiphemu swa nkombo, va ri tisa eka Yoxuwa entsongeni eXilo;”' },
    { n: 10, text: '“Yoxuwa a va hoxelana mpfhuka eXilo, mahlweni ka Yehovha; kutani Yoxuwa a avela vana va Israyele tiko hi ku ya hi swiphemu swa vona.”' },
    { n: 11, text: '“Kutani mpfhuka wa rixaka ra vana va Benjamini wu huma hi ku ya hi mindyangu ya vona; ndzilakano wa mpfhuka wa vona wu wela exikarhi ka vana va Yuda ni vana va Yosefa;”' },
    { n: 12, text: '“naswona ndzilakano wa vona hi vuxa bya n’walungu wu sungula eYordani; wu tlhandluka wu ya etlhelo ka Yeriko hi vuxa, wu tlhandluka entshaveni hi vupela-dyambu, wu hela emananga ya Beti-Aveni;”' },
    { n: 13, text: '“wu hundza kwalaho wu ya eLuzi, etlhelo ra Luzi (leri nga Beteli) hi dzonga; wu rhelela wu ya eAtarot-Adari, etlhelo ka ntshava leyi nga hi dzonga wa Bet-Oroni ya le hansi;”' },
    { n: 14, text: '“wu rhendzeleka wu hundza hi vupela-dyambu hi dzonga wa ntshava leyi nga mahlweni ka Bet-Oroni hi dzonga, wu hela eKiriati-Yearimi (leri nga Kiriati-Baali), muti wa vana va Yuda; lowu i tlhelo ra vupela-dyambu;”' },
    { n: 15, text: '“tlhelo ra dzonga wu sukela ekheleni ra Kiriati-Yearimi; wu ya hi vupela-dyambu, wu fika eswihlobyeni swa mati ya Neftowa;”' },
    { n: 16, text: '“wu rhelela wu ya ekheleni ra ntshava leyi nga mahlweni ka nkova wa n’wana wa Hinomu, lowu nga enkoveni wa Varefayi hi n’walungu, wu rhelela hi nkova wa Hinomu, etlhelo ka Vayebusi hi dzonga, wu rhelela eXihlobyeni xa Rogoeli;”' },
    { n: 17, text: '“wu rhendzeleka hi n’walungu, wu huma eEn-Xemexi, wu huma eGeliloti, leyi nga mahlweni ka ku tlhandluka ka Adumimi, wu rhelela eribyeni ra Bohani, n’wana wa Ruvene;”' },
    { n: 18, text: '“wu hundza etlhelo ra Arabah hi n’walungu, wu rhelela eArabah;”' },
    { n: 19, text: '“wu hundza etlhelo ra Beti-Hogla hi n’walungu; ndzilakano wu hela emaxikwini ya lwandle ra munyu hi n’walungu, ekheleni ra Yordani hi dzonga; lowu i ndzilakano wa dzonga;”' },
    { n: 20, text: '“Yordani i ndzilakano wa wona hi vuxa. Leyi i ndzhaka ya vana va Benjamini, hi ku ya hi mindyangu ya vona, hi ndzilakano ya vona hinkwayo;”' },
    { n: 21, text: '“naswona mimiti ya rixaka ra vana va Benjamini, hi ku ya hi mindyangu ya vona, a ku ri Yeriko, Beti-Hogla, Emeki-Kesisi,”' },
    { n: 22, text: '“Beti-Arabah, Zemarayimi, Beteli,”' },
    { n: 23, text: '“Avimi, Para, Ofra,”' },
    { n: 24, text: '“Kefar-Amonayi, Ofni, Gaba; mimiti ya khume-mbirhi ni matlhelo ya yona;”' },
    { n: 25, text: '“Gibiyoni, Rama, Beroti,”' },
    { n: 26, text: '“Mispa, Kefira, Mosa,”' },
    { n: 27, text: '“Rekemi, Yirpeeli, Tarala,”' },
    { n: 28, text: '“Zela, Elefe, Yebusi (leri nga Yerusalema), Gibiya, Kiriati; mimiti ya khume-mune ni matlhelo ya yona. Leyi i ndzhaka ya vana va Benjamini, hi ku ya hi mindyangu ya vona.”' }
  ],
  19: [
    { n: 1, text: '“Mpfhuka wa vumbirhi wu huma eka Simiyoni, eka rixaka ra vana va Simiyoni hi ku ya hi mindyangu ya vona; ndzhaka ya vona a yi ri exikarhi ka ndzhaka ya vana va Yuda;”' },
    { n: 2, text: '“naswona ndzhaka ya vona a yi ri Beer-Xeba, ni Xeba, ni Molada,”' },
    { n: 3, text: '“ni Hasari-Xuali, ni Bala, ni Esemi,”' },
    { n: 4, text: '“ni Eltoladi, ni Betuli, ni Horma,”' },
    { n: 5, text: '“ni Sikilagi, ni Beti-Markaboti, ni Hasari-Susa,”' },
    { n: 6, text: '“ni Beti-Lebayoti, ni Xaruheni; mimiti ya khume-nharhu ni matlhelo ya yona;”' },
    { n: 7, text: '“Ayini, Rimoni, Eteri, ni Axani; mimiti ya mune ni matlhelo ya yona;”' },
    { n: 8, text: '“ni mimiti hinkwayo leyi nga matlhelo ya mimiti leyi ku fika eBalati-Beer, leyi nga Ramata wa dzonga. Leyi i ndzhaka ya rixaka ra vana va Simiyoni, hi ku ya hi mindyangu ya vona;”' },
    { n: 9, text: '“ndzhaka ya vana va Simiyoni yi tekiwe eka mpfhuka wa vana va Yuda, hikuva xiphemu xa vana va Yuda a xi ri xikulu ngopfu eka vona; hikwalaho vana va Simiyoni va teke ndzhaka exikarhi ka ndzhaka ya vona;”' },
    { n: 10, text: '“Mpfhuka wa vunharhu wu huma eka vana va Zebuloni hi ku ya hi mindyangu ya vona; ndzilakano wa ndzhaka ya vona wu fika eSaridi;”' },
    { n: 11, text: '“ndzilakano wa vona wu tlhandluka hi vupela-dyambu eMarala, wu khumba Dabaxeti, wu fika enkoveni lowu nga mahlweni ka Yokineami;”' },
    { n: 12, text: '“wu tlhelela ku suka eSaridi hi vuxa, hi tlhelo ra le vuxeni, ku fika endzilakanweni wa Kisloti-Tabori, wu huma eDaberati, wu tlhandluka eYafiya;”' },
    { n: 13, text: '“wu hundza kwalaho hi vuxa ku ya eGati-Heferi, ni eEta-Kasini, wu huma eRimoni-Metuwari, wu rhendzeleka eNeya;”' },
    { n: 14, text: '“ndzilakano wu rhendzeleka hi n’walungu eHanatoni, wu hela enkoveni wa Yifta-Eli;”' },
    { n: 15, text: '“ni Katati, ni Nahalali, ni Ximroni, ni Yidala, ni Beti-Lehemi; mimiti ya khume-mbirhi ni matlhelo ya yona;”' },
    { n: 16, text: '“leyi i ndzhaka ya vana va Zebuloni, hi ku ya hi mindyangu ya vona, mimiti leyi ni matlhelo ya yona;”' },
    { n: 17, text: '“Mpfhuka wa mune wu huma eka Isakari, eka vana va Isakari hi ku ya hi mindyangu ya vona;”' },
    { n: 18, text: '“ndzilakano wa vona a wu ri Yezereyeli, ni Kesuloti, ni Xunemi,”' },
    { n: 19, text: '“ni Hafarayimi, ni Xiyonu, ni Anaharati,”' },
    { n: 20, text: '“ni Rabiti, ni Kixiyoni, ni Ebesi,”' },
    { n: 21, text: '“ni Remeti, ni En-Ganim, ni En-Hada, ni Beti-Pasesi,”' },
    { n: 22, text: '“ndzilakano wu khumba Tabori, ni Xahazima, ni Beti-Xemexi, wu hela eYordani; mimiti ya khume-mune ni matlhelo ya yona;”' },
    { n: 23, text: '“leyi i ndzhaka ya rixaka ra vana va Isakari, hi ku ya hi mindyangu ya vona, mimiti leyi ni matlhelo ya yona;”' },
    { n: 24, text: '“Mpfhuka wa ntlhanu wu huma eka rixaka ra vana va Axeri hi ku ya hi mindyangu ya vona;”' },
    { n: 25, text: '“ndzilakano wa vona a wu ri Helkati, ni Hali, ni Beteni, ni Akxafi,”' },
    { n: 26, text: '“ni Alameleki, ni Amadi, ni Mixali; ndzilakano wu khumba Karmeli hi vupela-dyambu, ni Xiori-Libnati;”' },
    { n: 27, text: '“wu tlhelela hi vuxa eBet-Dagoni, wu khumba Zebuloni, ni nkova wa Yifta-Eli hi n’walungu wa Beti-Emeki ni Neyeli, wu huma eKabuli hi ku ya hi n’walungu;”' },
    { n: 28, text: '“ni Ebroni, ni Rehobo, ni Hamoni, ni Kana, ku fika eSidoni lerikulu;”' },
    { n: 29, text: '“ndzilakano wu tlhelela eRama, ku fika emutini wa khokho wa Tiri, ndzilakano wu tlhelela eHosa, wu hela elwandle hi matlhelo ya Akzibi,”' },
    { n: 30, text: '“ni Uma, ni Afeka, ni Rehobo; mimiti ya khume-mbirhi-mune ni matlhelo ya yona;”' },
    { n: 31, text: '“leyi i ndzhaka ya rixaka ra vana va Axeri, hi ku ya hi mindyangu ya vona, mimiti leyi ni matlhelo ya yona;”' },
    { n: 32, text: '“Mpfhuka wa tsevu wu huma eka vana va Naftali, hi ku ya hi mindyangu ya vona;”' },
    { n: 33, text: '“ndzilakano wa vona wu huma eHelefi, eEloni-Beti-Saanayimi, ni Adami-Nekebi, ni Yabneeli, ku fika eLakumi, wu hela eYordani;”' },
    { n: 34, text: '“ndzilakano wu tlhelela hi vupela-dyambu eAznot-Tabori, wu huma kwalaho eHukoki, wu khumba Zebuloni hi dzonga, wu khumba Axeri hi vupela-dyambu, wu khumba Yuda hi vuxa ka Yordani;”' },
    { n: 35, text: '“mimiti ya khokho i Sidimi, Seri, Hamati, Rakati, ni Kinereti,”' },
    { n: 36, text: '“ni Adama, ni Rama, ni Hazori,”' },
    { n: 37, text: '“ni Kedexi, ni Edreyi, ni En-Hazori,”' },
    { n: 38, text: '“ni Yironi, Migdal-Eli, Horemi, Beti-Anati, ni Beti-Xemexi; mimiti ya khume-tsevu-mune ni matlhelo ya yona;”' },
    { n: 39, text: '“leyi i ndzhaka ya rixaka ra vana va Naftali, hi ku ya hi mindyangu ya vona, mimiti leyi ni matlhelo ya yona;”' },
    { n: 40, text: '“Mpfhuka wa nkombo wu huma eka rixaka ra vana va Dani hi ku ya hi mindyangu ya vona;”' },
    { n: 41, text: '“ndzilakano wa ndzhaka ya vona a wu ri Sora, ni Esetaoli, ni Iri-Xemexi,”' },
    { n: 42, text: '“ni Xaalabini, ni Ayaloni, ni Yitla,”' },
    { n: 43, text: '“ni Eloni, ni Timnata, ni Ekroni,”' },
    { n: 44, text: '“ni Elteke, ni Gibetoni, ni Balati,”' },
    { n: 45, text: '“ni Yehudi, ni Bene-Beraki, ni Gati-Rimoni,”' },
    { n: 46, text: '“ni Me-Yarkoni, ni Rakoni, ni ndzilakano lowu nga mahlweni ka Yopa;”' },
    { n: 47, text: '“kambe ndzilakano wa vana va Dani a wu va tsandzile, kutani vana va Dani va tlhandluka va ya lwa na Lexema, va yi teka, va yi ba hi banga, va tshama eka yona, va yi vitana Lexema-Dani, hi vito ra Dani tatana wa vona;”' },
    { n: 48, text: '“leyi i ndzhaka ya rixaka ra vana va Dani, hi ku ya hi mindyangu ya vona, mimiti leyi ni matlhelo ya yona;”' },
    { n: 49, text: '“loko va hete ku avela tiko hi ndzilakano wa rona, vana va Israyele va nyika Yoxuwa, n’wana wa Nuni, ndzhaka exikarhi ka vona;”' },
    { n: 50, text: '“hi rito ra Yehovha va n’wi nyika muti lowu a wu kombeleke, Timnata-Sera entshaveni ya Efrayimi; a aka muti, a tshama eka wona;”' },
    { n: 51, text: '“leyi i ndzhaka leyi Eleazari muprista, ni Yoxuwa n’wana wa Nuni, ni tindhuna ta tinyimba ta vana va Israyele, va yi aveleke hi mpfhuka eXilo mahlweni ka Yehovha, enyangweni wa tende ra ntsombano. Kutani va heta ku avela tiko.”' }
  ],
  20: [
    { n: 1, text: '“Yehovha a vulavula na Yoxuwa, a ku:”' },
    { n: 2, text: '“‘Byela vana va Israyele, u ku: “Tihlawuleleni mimiti ya vutumbelo, leyi ndzi mi byeleke ha yona hi ku tirhisa Muxe;’”' },
    { n: 3, text: '“‘leswaku loyi a dlayeke munhu hi xihoxo, a nga ri na xikongomelo, a ta balekela kwalaho; mimiti leyi yi ta va vutumbelo eka n’wina eka loyi a lavaka ku rihisela ngati;’”' },
    { n: 4, text: '“‘loyi a balekelaka eka yin’we ya mimiti leyi, u ta yima enyangweni wa muti, a hlamusela mhaka ya yena etindleveni ta vadyuhari va muti lowu; kutani va ta n’wi nghenisa emutini, va n’wi nyika ndhawu, leswaku a ta tshama exikarhi ka vona;’”' },
    { n: 5, text: '“‘naswona loko loyi a lavaka ku rihisela ngati a n’wi hlongorisa, va nga n’wi nyiketi eka yena, hikuva u dlaye munakwavo hi xihoxo, a nga n’wi venganga eku sunguleni;’”' },
    { n: 6, text: '“‘u ta tshama emutini lowu ku fika loko a yima mahlweni ka vandla ku avanyisiwa, ni ku fika loko muprista lonkulu a ta fa hi masiku wolawo; endzhaku ka sweswo loyi a dlayeke munhu a ta tlhelela emutini wa yena, ekaya ra yena, emutini lowu a baleke eka wona;’”' },
    { n: 7, text: '“kutani va hlawula Kedexi eGaleli, entshaveni ya Naftali, ni Xikemi entshaveni ya Efrayimi, ni Kiriati-Arba (lowu nga Hebroni) entshaveni ya Yuda;”' },
    { n: 8, text: '“ni le vuxa bya Yordani bya Yeriko, va hlawula Bezeri emananga, entshaveni ya Ruvene, ni Ramoti eGiliyadi, eka rixaka ra Gadi, ni Golani eBaxani, eka rixaka ra Manase;”' },
    { n: 9, text: '“leto a ku ri mimiti leyi hlawuriweke eka vana va Israyele hinkwavo, ni le ka mutambi loyi a nga mutshami exikarhi ka vona, leswaku un’wana ni un’wana loyi a dlayeke munhu hi xihoxo a balekela kwalaho, a nga fi hi voko ra loyi a lavaka ku rihisela ngati, ku fika loko a yima mahlweni ka vandla.”' }
  ],
  21: [
    { n: 1, text: '“Kutani tindhuna ta mindyangu ya Valevhi ti tshinela eka Eleazari muprista, ni le ka Yoxuwa n’wana wa Nuni, ni le ka tindhuna ta mindyangu ya tinyimba ta vana va Israyele;”' },
    { n: 2, text: '“ti va byela eXilo etikweni ra Kanana, ti ku: ‘Yehovha u lerise Muxe leswaku hi nyikiwa mimiti leyi hi nga ta tshama eka yona, ni matlhelo ya yona ya tihomu ta hina;’”' },
    { n: 3, text: '“vana va Israyele va nyika Valevhi, hi ndzhaka ya vona, hi ku ya hi rito ra Yehovha, mimiti leyi ni matlhelo ya yona;”' },
    { n: 4, text: '“mpfhuka wu huma eka mindyangu ya Vakehati; vana va Aroni muprista, lava nga Valevhi, va kuma mimiti ya khume-tsevu eka rixaka ra Yuda, ni le ka rixaka ra Simiyoni, ni le ka rixaka ra Benjamini, hi mpfhuka;”' },
    { n: 5, text: '“lava va seleke eka vana va Vakehati va kuma mimiti ya khume-mune eka mindyangu ya rixaka ra Efrayimi, ni le ka rixaka ra Dani, ni le ka hafu ya rixaka ra Manase, hi mpfhuka;”' },
    { n: 6, text: '“vavana va Gerxoni va kuma mimiti ya khume-nharhu eka mindyangu ya rixaka ra Isakari, ni le ka rixaka ra Axeri, ni le ka rixaka ra Naftali, ni le ka hafu ya rixaka ra Manase eBaxani, hi mpfhuka;”' },
    { n: 7, text: '“vavana va Merari, hi ku ya hi mindyangu ya vona, va kuma mimiti ya khume-mbirhi eka rixaka ra Ruvene, ni le ka rixaka ra Gadi, ni le ka rixaka ra Zebuloni;”' },
    { n: 8, text: '“vana va Israyele va nyika Valevhi mimiti leyi ni matlhelo ya yona, hi mpfhuka, hilaha Yehovha a leriseke Muxe hakona;”' },
    { n: 9, text: '“va nyika eka rixaka ra vana va Yuda, ni le ka rixaka ra vana va Simiyoni, mimiti leyi yi vitaniweke hi mavito;”' },
    { n: 10, text: '“kutani yi va eka vana va Aroni, va mindyangu ya Vakehati, eka vana va Levhi, hikuva mpfhuka wo sungula a wu ri wa vona;”' },
    { n: 11, text: '“va va nyika Kiriati-Arba (Arba a a ri tatana wa Anaki), lowu nga Hebroni, entshaveni ya Yuda, ni matlhelo ya wona;”' },
    { n: 12, text: '“kambe masimu ya muti ni matlhelo ya wona va ma nyika Kalebe, n’wana wa Yefune, hi ndzhaka ya yena;”' },
    { n: 13, text: '“eeka vana va Aroni muprista va nyika muti wa vutumbelo wa Hebroni ni matlhelo ya wona, ni Libna ni matlhelo ya yona,”' },
    { n: 14, text: '“ni Yatiri ni matlhelo ya yona, ni Esetemoa ni matlhelo ya yona,”' },
    { n: 15, text: '“ni Holoni ni matlhelo ya yona, ni Debiri ni matlhelo ya yona,”' },
    { n: 16, text: '“ni Ayni ni matlhelo ya yona, ni Yuta ni matlhelo ya yona, ni Beti-Xemexi ni matlhelo ya yona; mimiti ya khume-tsevu eka tinyimba leti timbirhi;”' },
    { n: 17, text: '“ni le ka rixaka ra Benjamini, Gibiyoni ni matlhelo ya yona, Geba ni matlhelo ya yona,”' },
    { n: 18, text: '“Anatoti ni matlhelo ya yona, ni Almoni ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 19, text: '“mimiti hinkwayo ya vana va Aroni, vaprista, a yi ri khume-tsevu-mune ni matlhelo ya yona;”' },
    { n: 20, text: '“minda-ngu ya vana va Vakehati, Valevhi lava va seleke eka vana va Vakehati, va kuma mimiti ya mpfhuka wa vona eka rixaka ra Efrayimi;”' },
    { n: 21, text: '“va va nyika muti wa vutumbelo wa Xikemi ni matlhelo ya wona entshaveni ya Efrayimi, ni Gezeri ni matlhelo ya yona,”' },
    { n: 22, text: '“ni Kibisayimi ni matlhelo ya yona, ni Beti-Oroni ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 23, text: '“ni le ka rixaka ra Dani, Elteke ni matlhelo ya yona, Gibetoni ni matlhelo ya yona,”' },
    { n: 24, text: '“ni Ayaloni ni matlhelo ya yona, Gati-Rimoni ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 25, text: '“ni le ka hafu ya rixaka ra Manase, Taanaki ni matlhelo ya yona, Gati-Rimoni ni matlhelo ya yona; mimiti ya mimbirhi;”' },
    { n: 26, text: '“mimiti hinkwayo ya mindyangu ya vana va Vakehati lava va seleke a yi ri khume-mune ni matlhelo ya yona;”' },
    { n: 27, text: '“vavana va Gerxoni, eka mindyangu ya Valevhi, va nyikiwa eka hafu ya rixaka ra Manase, muti wa vutumbelo wa Golani eBaxani ni matlhelo ya wona, ni Beextera ni matlhelo ya yona; mimiti ya mimbirhi;”' },
    { n: 28, text: '“ni le ka rixaka ra Isakari, Kixiyoni ni matlhelo ya yona, Daberati ni matlhelo ya yona,”' },
    { n: 29, text: '“Yarmuti ni matlhelo ya yona, En-Ganim ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 30, text: '“ni le ka rixaka ra Axeri, Mixali ni matlhelo ya yona, Abidoni ni matlhelo ya yona,”' },
    { n: 31, text: '“Helkati ni matlhelo ya yona, Rehobo ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 32, text: '“ni le ka rixaka ra Naftali, muti wa vutumbelo wa Kedexi eGaleli ni matlhelo ya wona, Hamoti-Dori ni matlhelo ya yona, Kartani ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 33, text: '“mimiti hinkwayo ya Gerxoni, hi ku ya hi mindyangu ya vona, a yi ri khume-tsevu-mune ni matlhelo ya yona;”' },
    { n: 34, text: '“ni eka mindyangu ya vana va Merari, Valevhi lava va seleke, va kuma eka rixaka ra Zebuloni, Yokineami ni matlhelo ya yona, Karta ni matlhelo ya yona,”' },
    { n: 35, text: '“Dimna ni matlhelo ya yona, Nahalali ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 36, text: '“ni le ka rixaka ra Ruvene, Bezeri ni matlhelo ya yona, Yasa ni matlhelo ya yona,”' },
    { n: 37, text: '“Kedemoti ni matlhelo ya yona, Mefati ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 38, text: '“ni le ka rixaka ra Gadi, muti wa vutumbelo wa Ramoti eGiliyadi ni matlhelo ya wona, Mahanayimi ni matlhelo ya yona,”' },
    { n: 39, text: '“Hesiboni ni matlhelo ya yona, Yazeri ni matlhelo ya yona; mimiti ya mune;”' },
    { n: 40, text: '“mimiti hinkwayo ya vana va Merari, hi ku ya hi mindyangu ya vona, lava va seleke eka mindyangu ya Valevhi, hi mpfhuka wa vona, a yi ri khume-mbirhi ni mimbirhi;”' },
    { n: 41, text: '“mimiti hinkwayo ya Valevhi exikarhi ka ndzhaka ya vana va Israyele a yi ri khume-mune-mbirhi ni khume-mune-mbirhi ni matlhelo ya yona;”' },
    { n: 42, text: '“mimiti leyi hinkwayo a yi ri ni matlhelo ya yona ku rhendzela; mimiti hinkwayo a yi ri tano;”' },
    { n: 43, text: '“Yehovha a nyika Israyele tiko hinkwaro leri a a hlambanyele vatata wa vona leswaku u ta ri nyika, kutani va tshama eka rona;”' },
    { n: 44, text: '“Yehovha a va nyika ku rhula matlhelo hinkwawo, hilaha a hlambanyeleke vatata wa vona hakona; a ku na un’we wa valala va vona loyi a yimeke mahlweni ka vona; Yehovha u nyikete valala hinkwavo evokweni ra vona;”' },
    { n: 45, text: '“a ku na rito na rin’we eka switshembiso hinkwaswo leswinene leswi Yehovha a swi tshembiseke yindlu ya Israyele, leri nga hetisekangiki; hinkwaswo swi endlekile.”' }
  ],
  22: [
    { n: 1, text: '“Kutani Yoxuwa a vitana Varuvheni, Vagadi, ni hafu ya rixaka ra Manase,”' },
    { n: 2, text: '“a ku eka vona: ‘Mi hlayise hinkwaswo leswi Muxe, nandza wa Yehovha, a mi leriseke swona, naswona mi yingisile rito ra mina eka hinkwaswo leswi ndzi mi leriseke swona;’”' },
    { n: 3, text: '“‘mi nga va tshikanga vamakwerhu hi masiku lawa hinkwawo ku fikela namuntlha, kambe mi hlayise nawu wa Yehovha Xikwembu xa n’wina;’”' },
    { n: 4, text: '“‘sweswi Yehovha Xikwembu xa n’wina u nyike vamakwerhu ku rhula, hilaha a va tshembiseke hakona; kutani sweswi tlhelelani emintsongeni ya n’wina, etikweni ra ndzhaka ya n’wina, leri Muxe, nandza wa Yehovha, a mi nyikeke rona hi vuxa ka Yordani;’”' },
    { n: 5, text: '“‘kambe tiyisisani leswaku mi hlayisa nawu lowu Muxe a mi leriseke wona, mi rhandza Yehovha Xikwembu xa n’wina, mi famba etindleleni ta yena hinkwato, mi hlayisa swileriso swa yena, mi namarhela eka yena, mi n’wi tirhela hi mbilu ya n’wina hinkwayo.’”' },
    { n: 6, text: '“Yoxuwa a va katekisa, a va rhuma, kutani va ya emintsongeni ya vona.”' },
    { n: 7, text: '“Muxe a a nyike hafu ya rixaka ra Manase ndzhaka eBaxani, kambe hafu leyi yin’wana Yoxuwa a va nyike yona exikarhi ka vamakwerhu hi vupela-dyambu bya Yordani; kutani loko Yoxuwa a va rhuma emintsongeni ya vona, a va katekisa;”' },
    { n: 8, text: '“a ku eka vona: ‘Tlhelelani emintsongeni ya n’wina mi ri na rifuwo lerikulu, mi ri na swifuwo swo tala, mi ri na silivhere, nsuku, nsimbi, ni swiambalo swo tala; avanelani ntsengo wa valala va n’wina ni vamakwerhu.’”' },
    { n: 9, text: '“Kutani vana va Ruvene, na vana va Gadi, ni hafu ya rixaka ra Manase va tlhelela, va suka eXilo, etikweni ra Kanana, va tlhelela etikweni ra Giliyadi, ndzhaka ya vona, leyi va yi teke hi rito ra Yehovha hi ku tirhisa Muxe.”' },
    { n: 10, text: '“Kutani loko va fika emaxikwini ya Yordani, leyi nga etikweni ra Kanana, vana va Ruvene, na vana va Gadi, ni hafu ya rixaka ra Manase va aka altari kwalaho ekusuhi na Yordani, altari leyikulu leyi vonakaka.”' },
    { n: 11, text: '“Kutani vana va Israyele va twa va ku: ‘Vonani, vana va Ruvene, na vana va Gadi, ni hafu ya rixaka ra Manase va akile altari mahlweni ka tiko ra Kanana, emaxikwini ya Yordani, etlhelo leri nga ra vana va Israyele.’”' },
    { n: 12, text: '“Kutani vandla hinkwaro ra vana va Israyele ri hlengeletana eXilo, leswaku ri ya lwa na vona.”' },
    { n: 13, text: '“Kutani vana va Israyele va rhuma Finehasi, n’wana wa Eleazari muprista, a ya etikweni ra Giliyadi, eka vana va Ruvene, na vana va Gadi, ni hafu ya rixaka ra Manase,”' },
    { n: 14, text: '“va ri na tindhuna ta khume, ndhuna yin’we hi yindlu ya tatana eka tinyimba hinkwato ta Israyele, un’wana ni un’wana a a ri ndhuna ya yindlu ya tatana exikarhi ka vana va Israyele.”' },
    { n: 15, text: '“Va fika eka vana va Ruvene, na vana va Gadi, ni hafu ya rixaka ra Manase, etikweni ra Giliyadi, va vulavula na vona, va ku:”' },
    { n: 16, text: '“‘Vandla hinkwaro ra Yehovha ri vutisa ri ku: “I yini xidyoho lexi mi xi endleke eka Xikwembu xa Israyele, hi ku tlhela namuntlha eka Yehovha, hi ku tiakela altari, leswaku mi xika namuntlha eka Yehovha?”’”' },
    { n: 17, text: '“‘Xana xidyoho xa Peori a xi hi ringananga, lexi hi nga xi endla ku fikela namuntlha, lexi vangeleke vuvabyi exikarhi ka vandla ra Yehovha?’”' },
    { n: 18, text: '“‘kambe n’wina mi tlhela namuntlha eka Yehovha; naswona loko mi xika na n’wina eka Yehovha namuntlha, mundzuku u ta hlundzukela vandla hinkwaro ra Israyele.’”' },
    { n: 19, text: '“‘Kambe loko tiko ra ndzhaka ya n’wina ri ri ro nyamela, xikani etikweni ra ndzhaka ya Yehovha, laha tende ra Yehovha ri nga kona, mi teka swiphemu exikarhi ka hina; kambe mi nga xikani eka Yehovha, mi nga hi xikani, hi ku tiakela altari handle ka altari ya Yehovha Xikwembu xa hina.’”' },
    { n: 20, text: '“‘Xana Akani n’wana wa Zera a a nga endlanga xidyoho eka leswi a swi hlawuriweke, kutani vukari bya Yehovha byi wela ehenhla ka vandla hinkwaro ra Israyele? Yena a a nga fi yexe hi xidyoho xa yena.’”' },
    { n: 21, text: '“Kutani vana va Ruvene, na vana va Gadi, ni hafu ya rixaka ra Manase va hlamula, va byela tindhuna ta tinyimba ta Israyele, va ku:”' },
    { n: 22, text: '“‘Yehovha Xikwembu xa swikwembu, Yehovha Xikwembu xa swikwembu, u swi tiva, na Israyele u ta swi tiva; loko a ku ri hi ku xika kumbe hi ku dyohela Yehovha, u nga hi ponisi namuntlha;’”' },
    { n: 23, text: '“‘leswaku hi tiakela altari hi ku tlhela eka Yehovha, kumbe hi ku endla magandzelo ehenhla ka yona, kumbe hi ku endla magandzelo ya ku rhula, Yehovha hi Yexe a a hi tshinyi;’”' },
    { n: 24, text: '“‘nikatsongo, hi swi endle hikwalaho ka ku chava mhaka leyi, hi ku: “Mundzuku vana va n’wina va nga byela vana va hina, va ku: ‘Mi na mhaka muni na Yehovha Xikwembu xa Israyele?’”’”' },
    { n: 25, text: '“‘“hikuva Yehovha u veke Yordani ndzilakano exikarhi ka hina na n’wina, vana va Ruvene na vana va Gadi; mi hava xiphemu eka Yehovha; kutani vana va n’wina va nga endla vana va hina va tshika ku chava Yehovha.”’”' },
    { n: 26, text: '“‘Hikwalaho hi te: “A hi tiakelen altari, ku nga ri ya magandzelo, ku nga ri ya magandzelo ya ku hisiwa;”’”' },
    { n: 27, text: '“‘“kambe yi va mbhoni exikarhi ka hina na n’wina, ni mixaka ya hina leyi taka endzhaku ka hina, leswaku hi tirhela Yehovha mahlweni ka yena hi magandzelo ya hina ya ku hisiwa, ni magandzelo ya hina ya ku rhula, leswaku vana va n’wina va nga byeli vana va hina mundzuku, va ku: ‘Mi hava xiphemu eka Yehovha.’”’”' },
    { n: 28, text: '“‘Hikwalaho hi te: “Loko va byela hina kumbe vana va hina mundzuku, hi ta ku: ‘Vonani xikombiso xa altari ya Yehovha, leyi vatata wa hina va yi endleke, ku nga ri ya magandzelo, ku nga ri ya ku hisiwa, kambe i mbhoni exikarhi ka hina na n’wina.’”’”' },
    { n: 29, text: '“‘A swi nge endleki eka hina ku tlhela eka Yehovha, ni ku tshika ku tirhela Yehovha namuntlha, hi ku tiakela altari ya magandzelo ya ku hisiwa, kumbe ya magandzelo ya swakudya, kumbe ya magandzelo ya ku rhula, handle ka altari ya Yehovha Xikwembu xa hina leyi nga mahlweni ka tende ra yena.’”' },
    { n: 30, text: '“Kutani Finehasi muprista, ni tindhuna ta vandla, lava a va ri na yena, tindhuna ta tinyimba ta Israyele, va twa marito lawa vana va Ruvene, na vana va Gadi, ni vana va Manase va ma vuleke, kutani swi va tsakisa.”' },
    { n: 31, text: '“Finehasi n’wana wa Eleazari muprista, a ku eka vana va Ruvene, na vana va Gadi, ni vana va Manase: ‘Namuntlha hi swi tiva leswaku Yehovha u exikarhi ka hina, hikuva a mi endlanga xidyoho lexi eka Yehovha; sweswi mi ponise vana va Israyele evokweni ra Yehovha.’”' },
    { n: 32, text: '“Kutani Finehasi n’wana wa Eleazari muprista, ni tindhuna, va tlhela va suka eka vana va Ruvene, na vana va Gadi, etikweni ra Giliyadi, va ya etikweni ra Kanana, eka vana va Israyele, va va tivisa mhaka yoleyo.”' },
    { n: 33, text: '“Mhaka yoleyo yi tsakisa vana va Israyele; vana va Israyele va nkhensa Xikwembu, a va ha vulavulanga hi ku ya lwa na vona, leswaku va onha tiko leri vana va Ruvene na vana va Gadi a va tshama eka rona.”' },
    { n: 34, text: '“Kutani vana va Ruvene na vana va Gadi va yi thya altari yoleyo vito ra Edi; hikuva va ku: ‘I mbhoni exikarhi ka hina leswaku Yehovha i Xikwembu.’”' }
  ],
  23: [
    { n: 1, text: '“Ku hundze nkarhi wo tala endzhaku ka loko Yehovha a nyike Israyele ku rhula eka valala va vona hinkwavo, Yoxuwa u dyuharile;”' },
    { n: 2, text: '“Yoxuwa a vitana Israyele hinkwavo, vadyuhari va vona, tindhuna ta vona, vaavanyisi va vona, ni valanguteri va vona, a ku eka vona: ‘Ndzi dyuharile, ndzi kule ngopfu;’”' },
    { n: 3, text: '“‘mi vone hinkwaswo leswi Yehovha Xikwembu xa n’wina a swi endleke eka matiko lawa hinkwawo hikwalaho ka n’wina, hikuva Yehovha Xikwembu xa n’wina hi yena loyi a a mi lwela;’”' },
    { n: 4, text: '“‘vonani, ndzi mi avele matiko lawa ya vaaki va wona hi mpfhuka, ku suka eYordani ku fika elwandle lerikulu, matiko hinkwawo lawa ndzi ma hluleke;’”' },
    { n: 5, text: '“‘Yehovha Xikwembu xa n’wina u ta va hlongola mahlweni ka n’wina, mi ta teka tiko ra vona, hilaha Yehovha Xikwembu xa n’wina a mi tshembiseke hakona.’”' },
    { n: 6, text: '“‘Hikwalaho, tiyisisani swinene leswaku mi hlayisa mi tlhela mi endla hinkwaswo leswi swi tsariweke emugwadzini wa nawu wa Muxe, leswaku mi nga hambuki eka wona, mi nga yi eka voko ra xinene kumbe ra ximati;’”' },
    { n: 7, text: '“‘leswaku mi nga hlanganisi na matiko lawa lama seleke exikarhi ka n’wina; mi nga vuli mavito ya swikwembu swa vona, mi nga swi hlambanyeli, mi nga swi tirheli, mi nga swi khizameli;’”' },
    { n: 8, text: '“‘kambe namarhelani eka Yehovha Xikwembu xa n’wina, hilaha mi endleke hakona ku fikela namuntlha.’”' },
    { n: 9, text: '“‘Hikuva Yehovha u hlongole matiko lamakulu ni ya matimba mahlweni ka n’wina; eka n’wina a ku na un’we wa valala loyi a yimeke mahlweni ka n’wina ku fikela namuntlha.’”' },
    { n: 10, text: '“‘Un’we wa n’wina u ta hlongola khume wa va le matikweni, hikuva Yehovha Xikwembu xa n’wina hi yena loyi a a mi lwela, hilaha a mi tshembiseke hakona.’”' },
    { n: 11, text: '“‘Hikwalaho, tiyisisani swinene leswaku mi rhandza Yehovha Xikwembu xa n’wina.’”' },
    { n: 12, text: '“‘Hikuva loko mi tlhela, mi namarhela eka lava va seleke eka matiko lawa lama seleke exikarhi ka n’wina, mi teka vavasati va vona, mi hlangana na vona, na vona va hlangana na n’wina;’”' },
    { n: 13, text: '“‘tivani kahle leswaku Yehovha Xikwembu xa n’wina a nge he va hlongoli matiko lawa mahlweni ka n’wina; kambe ma ta va ntlhamu ni xihinga eka n’wina, ni ntswa eka matlhelo ya n’wina, ni mitwa etinhlohweni ta n’wina, ku fikela loko mi hera etikweni leri rinene leri Yehovha Xikwembu xa n’wina a mi nyikeke rona.’”' },
    { n: 14, text: '“‘Sweswi ndzi le ku feni, naswona mi swi tiva hi mbilu ya n’wina hinkwayo ni moya wa n’wina hinkwawo, leswaku a ku na rito na rin’we eka switshembiso hinkwaswo leswinene leswi Yehovha Xikwembu xa n’wina a swi tshembiseke leswi nga tsandzekiki; hinkwaswo swi endlekile, a ku na rito na rin’we leri nga endlekangiki.’”' },
    { n: 15, text: '“‘Naswona hilaha switshembiso hinkwaswo leswinene leswi Yehovha Xikwembu xa n’wina a swi tshembiseke, swi nga ta humelela ehenhla ka n’wina, hi hilaha Yehovha a nga ta tisa switshembiso hinkwaswo swo biha ehenhla ka n’wina, ku fikela loko a mi herisa etikweni leri rinene leri Yehovha Xikwembu xa n’wina a mi nyikeke rona.’”' },
    { n: 16, text: '“‘Loko mi tlula ntwanano wa Yehovha Xikwembu xa n’wina, lowu a mi leriseke wona, mi ya tirhela swikwembu swin’wana, mi swi khizamela, vukari bya Yehovha byi ta mi pfurhela, kutani mi ta hatla mi hela etikweni leri rinene leri a mi nyikeke rona.’”' }
  ],
  24: [
    { n: 1, text: '“Yoxuwa a hlengeletana na tinyimba hinkwato ta Israyele eXikemi; a vitana vadyuhari va Israyele, tindhuna ta vona, vaavanyisi va vona, ni valanguteri va vona; va yima mahlweni ka Xikwembu.”' },
    { n: 2, text: '“Yoxuwa a ku eka vanhu hinkwavo: ‘Leswi hi leswi Yehovha Xikwembu xa Israyele a swi vulaka: “Vatata wa n’wina va tshame evuxa bya Yordani khale, Terah, tata wa Abrahama na Nahori; kutani va tirhele swikwembu swin’wana;”’”' },
    { n: 3, text: '“‘“kambe ndzi teke tata wa n’wina Abrahama hi le vuxa bya Yordani, ndzi n’wi fambisa etikweni hinkwaro ra Kanana, ndzi andzisa vana va yena, ndzi n’wi nyika Isaka;”’”' },
    { n: 4, text: '“‘“ndzi nyika Isaka Yakobo na Esawu; ndzi nyika Esawu ntshava ya Seyiri leswaku a yi teka, kambe Yakobo ni vana va yena va xika eEgipta;”’”' },
    { n: 5, text: '“‘“ndzi rhuma Muxe na Aroni, ndzi ba Egipta hi leswi ndzi swi endleke exikarhi ka vona; endzhaku ka sweswo ndzi mi humesile;”’”' },
    { n: 6, text: '“‘“ndzi humesa vatata wa n’wina eEgipta, mi fika elwandle; vaEgipta va hlongorisa vatata wa n’wina hi makalichi ni vageleta ku fika elwandle ro tshwuka;”’”' },
    { n: 7, text: '“‘“va huwelela eka Yehovha, kutani a veka munyama exikarhi ka n’wina na vaEgipta, a tisa lwandle ehenhla ka vona, ri va funengeta; mahlo ya n’wina ma vone leswi ndzi swi endleke eEgipta; mi tshame emananga nkarhi wo leha;”’”' },
    { n: 8, text: '“‘“ndzi mi yisa etikweni ra Vaamori, lava a va tshama hi vuxa bya Yordani, va lwa na n’wina; ndzi va nyiketa evokweni ra n’wina, mi teka tiko ra vona, ndzi va herisa mahlweni ka n’wina;”’”' },
    { n: 9, text: '“‘“Balaki n’wana wa Sipori, hosi ya Mowabu, a suka a lwa na Israyele, a rhuma a vitana Balamu n’wana wa Bewori leswaku a mi rhukana;”’”' },
    { n: 10, text: '“‘“kambe a ndzi lavanga ku yingisa Balamu; u mi katekise ngopfu, kutani ndzi mi ponisile evokweni ra yena;”’”' },
    { n: 11, text: '“‘“mi tsemakanya Yordani, mi fika eYeriko; vavanuna va Yeriko, Vaamori, Vaperizi, Vakanana, Vahiti, Vagirgasi, Vahivi, ni Vayebusi va lwa na n’wina, kutani ndzi va nyiketa evokweni ra n’wina;”’”' },
    { n: 12, text: '“‘“ndzi rhuma timhungu mahlweni ka n’wina, leti ti va hlongoleke mahlweni ka n’wina, tihosi timbirhi ta Vaamori, a ku ri hi banga ra n’wina kumbe hi vurha bya n’wina;”’”' },
    { n: 13, text: '“‘“ndzi mi nyika tiko leri mi nga tirhelangiki eka rona, ni mimiti leyi mi nga yi ahelangiki, kutani mi tshama eka yona; mi dya swirero leswi mi nga swi byalangiki ni mintsumbu leyi mi nga yi cukumetangiki.”’”' },
    { n: 14, text: '“‘Sweswi, chavani Yehovha, mi n’wi tirhela hi mbilu leyi heleleke, mi susa swikwembu leswi vatata wa n’wina va swi tirheleke hi le vuxa bya Yordani ni le Egipta, mi tirhela Yehovha;’”' },
    { n: 15, text: '“‘naswona loko mi nga swi tsakeli ku tirhela Yehovha, hlawulani namuntlha loyi mi nga ta n’wi tirhela; kambe mina ni yindlu ya mina, hi ta tirhela Yehovha.’”' },
    { n: 16, text: '“Vanhu va hlamula, va ku: ‘A swi nge endleki eka hina ku tshika Yehovha leswaku hi tirhela swikwembu swin’wana;’”' },
    { n: 17, text: '“‘hikuva Yehovha Xikwembu xa hina, hi yena loyi a hi humeseke ni vatata wa hina etikweni ra Egipta, hi ku tirha hi vuhlonga, a endla masingita lawa lamakulu mahlweni ka hina, a hi hlayisa etindleleni hinkwato leti hi fambeke ha tona, ni le mahlweni ka matiko hinkwawo lawa hi tsemakanyeke eka wona;’”' },
    { n: 18, text: '“‘Yehovha u hlongole matiko hinkwawo mahlweni ka hina, ni Vaamori, vaaki va tiko leri; hikwalaho na hina hi ta tirhela Yehovha, hikuva hi yena Xikwembu xa hina.’”' },
    { n: 19, text: '“Yoxuwa a ku eka vanhu: ‘Mi nge swi koti ku tirhela Yehovha, hikuva i Xikwembu xo kwetsima, i Xikwembu lexi nga ni vukari, a nge mi rivaleli ku tlula ka n’wina ni swidyoho swa n’wina;’”' },
    { n: 20, text: '“‘loko mi tshika Yehovha, mi tirhela swikwembu swin’wana, u ta tlhelela a mi endla swo biha, a mi herisa, endzhaku ka loko a mi endlele leswinene.’”' },
    { n: 21, text: '“Vanhu va ku eka Yoxuwa: ‘E-e, hi ta tirhela Yehovha.’”' },
    { n: 22, text: '“Yoxuwa a ku eka vanhu: ‘Mi timbhoni ehenhla ka n’wina leswaku mi tihlawulele Yehovha leswaku mi n’wi tirhela.’ Va ku: ‘Hi timbhoni.’”' },
    { n: 23, text: '“‘Sweswi susani swikwembu swin’wana leswi nga exikarhi ka n’wina, mi tlhelisela timbilu ta n’wina eka Yehovha Xikwembu xa Israyele.’”' },
    { n: 24, text: '“Vanhu va ku eka Yoxuwa: ‘Hi ta tirhela Yehovha Xikwembu xa hina, naswona hi ta yingisa rito ra yena.’”' },
    { n: 25, text: '“Kutani Yoxuwa a endla ntwanano ni vanhu hi siku rero, a va vekela nawu ni xileriso eXikemi;”' },
    { n: 26, text: '“Yoxuwa a tsala marito lawa emugwadzini wa nawu wa Xikwembu; a teka ribye lerikulu, a ri yimisa kwalaho, ehansi ka nkuwa lowu a wu ri ekusuhi ni ndhawu leyi kwetsimaka ya Yehovha;”' },
    { n: 27, text: '“Yoxuwa a ku eka vanhu hinkwavo: ‘Vonani, ribye leri ri ta va mbhoni ehenhla ka hina, hikuva ri twile marito hinkwavo lawa Yehovha a ma vuleke eka hina; ri ta va mbhoni ehenhla ka n’wina, leswaku mi nga hembi eka Xikwembu xa n’wina.’”' },
    { n: 28, text: '“Kutani Yoxuwa a rhuma vanhu, un’wana ni un’wana a tlhelela endzhawini ya ndzhaka ya yena.”' },
    { n: 29, text: '“Endzhaku ka sweswo Yoxuwa, n’wana wa Nuni, nandza wa Yehovha, a fa, a ri ni malembe ya khume-khume ni mune;”' },
    { n: 30, text: '“va n’wi lahla endzhawini ya ndzhaka ya yena eTimnata-Sera, leyi nga entshaveni ya Efrayimi, hi n’walungu wa ntshava ya Gaaxi;”' },
    { n: 31, text: '“Israyele u tirhele Yehovha hi masiku hinkwawo ya Yoxuwa, ni masiku hinkwawo ya vadyuhari lava va hanyeke endzhaku ka Yoxuwa, lava a va swi tiva hinkwaswo leswi Yehovha a swi endleke eka Israyele;”' },
    { n: 32, text: '“marhambo ya Yosefa, lawa vana va Israyele va ma humeseke eEgipta, va ma lahla eXikemi, entshaveni leyi Yakobo a yi xaveke eka vana va Hamori, tatana wa Xikemi, hi mali ya dzana ra mali, kutani yi va ndzhaka ya vana va Yosefa;”' },
    { n: 33, text: '“Eleazari n’wana wa Aroni na yena a fa; va n’wi lahla eGibeha ya Finehasi n’wana wa yena, leyi a yi nyikiweke yona entshaveni ya Efrayimi.”' }
  ]
  
};
